-12 col-md-12 col-lg-12 col-xl-12\"\r\n                      v-for=\"(order_pend, indexx) in localOrden\"\r\n                      :key=\"indexx\"\r\n                    >\r\n                      <!--  -->\r\n                      <div\r\n                        class=\"\r\n                          mx-2\r\n                          coupon\r\n                          rounded\r\n                          d-flex\r\n                          justify-content-between\r\n                        \"\r\n                      >\r\n                        <div\r\n                          class=\"\r\n                            tengah\r\n                            py-2\r\n                            d-flex\r\n                            w-100\r\n                            justify-content-start\r\n                            p-2\r\n                          \"\r\n                        >\r\n                          <div\r\n                            class=\"\r\n                              col-md-12\r\n                              overflow-hidden\r\n                              card\r\n                              shadow-lg\r\n                              p-3\r\n                              rounded\r\n                            \"\r\n                            style=\"\r\n                              box-shadow: 0 1rem 3rem rgb(0 0 0 / 18%) !important;\r\n                            \"\r\n                          >\r\n                            <div class=\"row\">\r\n                              <h3 class=\"lead font-weight-light\">\r\n                                {{ order_pend.food.description.toUpperCase() }}\r\n                                <span\r\n                                  v-if=\"order_pend.type_id\"\r\n                                  class=\"text-primary\"\r\n                                >\r\n                                  <small>\r\n                                    <strong\r\n                                      >*{{\r\n                                        order_pend.type_description\r\n                                      }}</strong\r\n                                    >\r\n                                  </small>\r\n                                </span>\r\n                              </h3>\r\n                              <p\r\n                                class=\"\r\n                                  badge\r\n                                  bg-foreground\r\n                                  text-uppercase\r\n                                  font-weight-light\r\n                                  p-0\r\n                                \"\r\n                              ></p>\r\n                            </div>\r\n                            <div class=\"row col-12\">\r\n                              <div\r\n                                class=\"col-2 col-md-2\"\r\n                                v-if=\"!configuration.college\"\r\n                              >\r\n                                <el-tag\r\n                                  v-if=\"configuration.restaurant\"\r\n                                  @click=\"toCarry(indexx)\"\r\n                                  size=\"medium\"\r\n                                  role=\"button\"\r\n                                  :type=\"\r\n                                    order_pend.to_carry ? 'success' : 'info'\r\n                                  \"\r\n                                  :effect=\"\r\n                                    order_pend.to_carry ? 'dark' : 'plain'\r\n                                  \"\r\n                                >\r\n                                  <i\r\n                                    class=\"fas fa-biking\"\r\n                                    style=\"color: black\"\r\n                                  ></i>\r\n                                </el-tag>\r\n                              </div>\r\n                              <div class=\"col-4 col-md-4\">\r\n                                <el-button-group>\r\n                                  <el-button\r\n                                    class=\"text-white\"\r\n                                    type=\"danger\"\r\n                                    icon=\"el-icon-delete\"\r\n                                    size=\"mini\"\r\n                                    circle\r\n                                    @click=\"deleteFood(indexx)\"\r\n                                  >\r\n                                  </el-button>\r\n                                  <el-button\r\n                                    v-if=\"\r\n                                      configuration.restaurant &&\r\n                                      !configuration.college\r\n                                    \"\r\n                                    class=\"text-white\"\r\n                                    type=\"info\"\r\n                                    icon=\"el-icon-s-order\"\r\n                                    size=\"mini\"\r\n                                    circle\r\n                                    @click=\"\r\n                                      openLocalObservationDialog(\r\n                                        indexx,\r\n                                        order_pend.observation\r\n                                      )\r\n                                    \"\r\n                                  >\r\n                                  </el-button>\r\n                                </el-button-group>\r\n                              </div>\r\n                            </div>\r\n\r\n                            <div class=\"row align-items-end\">\r\n                              <div class=\"col-4 col-md-5 col-lg-4 col-xl-4\">\r\n                                <span class=\"text-muted\">\r\n                                  Cantidad<br />\r\n                                  <div\r\n                                    class=\"input-group spinner\"\r\n                                    data-trigger=\"spinner\"\r\n                                  >\r\n                                    <input\r\n                                      type=\"text\"\r\n                                      :readonly=\"  !configuration.quantity_cash  || order_pend.food.item.series_enabled ==  1 || (order_pend.food.item.lots_enabled ==  1 && order_pend.food.item.lots_group .length > 1)  \"\r\n                                      class=\"form-control text-center\"\r\n                                      v-model=\"order_pend.quantity\"\r\n                                      data-rule=\"currency\"\r\n                                      @input=\"verifyStock(order_pend, indexx)\"\r\n                                    />\r\n                                    <div class=\"input-group-text\">\r\n                                      <button\r\n                                        type=\"button\"\r\n                                        class=\"spin-up\"\r\n                                        data-spin=\"up\"\r\n                                        :disabled=\"\r\n                                          order_pend.food.item.series_enabled ==\r\n                                            1 ||\r\n                                          (order_pend.food.item.lots_enabled ==\r\n                                            1 &&\r\n                                            order_pend.food.item.lots_group\r\n                                              .length > 1)\r\n                                        \"\r\n                                        @click=\"sumar_orden(indexx)\"\r\n                                      >\r\n                                        <span class=\"arrow\"></span>\r\n                                      </button>\r\n                                      <button\r\n                                        type=\"button\"\r\n                                        class=\"spin-down\"\r\n                                        data-spin=\"down\"\r\n                                        :disabled=\"\r\n                                          order_pend.food.item.series_enabled ==\r\n                                            1 ||\r\n                                          (order_pend.food.item.lotes_enabled ==\r\n                                            1 &&\r\n                                            order_pend.food.item.lots_group\r\n                                              .length > 1)\r\n                                        \"\r\n                                        @click=\"restar_orden(indexx)\"\r\n                                      >\r\n                                        <span class=\"arrow\"></span>\r\n                                      </button>\r\n                                    </div>\r\n                                  </div>\r\n                                </span>\r\n                              </div>\r\n                              <div class=\"col-4 col-md-5 col-lg-5 col-xl-4\">\r\n                                <span class=\"time font-weight-light\">\r\n                                  <span class=\"text-muted\">\r\n                                    Precio\r\n                                    <br />\r\n                                    <el-input\r\n                                      class=\"custom_input\"\r\n                                      :disabled=\"\r\n                                        order_pend.type_id != null ||\r\n                                        configuration.edit_price_sales == false\r\n                                      \"\r\n                                      type=\"number\"\r\n                                      v-model=\"order_pend.price\"\r\n                                      @input=\"\r\n                                        update_price(indexx, order_pend.price)\r\n                                      \"\r\n                                    >\r\n                                      <template\r\n                                        slot=\"prepend\"\r\n                                        v-if=\"\r\n                                          order_pend.food.item\r\n                                            .currency_type_id == 'PEN'\r\n                                        \"\r\n                                      >\r\n                                        S/\r\n                                      </template>\r\n                                      <template\r\n                                        slot=\"prepend\"\r\n                                        v-if=\"\r\n                                          order_pend.food.item\r\n                                            .currency_type_id == 'USD'\r\n                                        \"\r\n                                      >\r\n                                        $\r\n                                      </template>\r\n                                    </el-input>\r\n                                  </span>\r\n                                </span>\r\n                              </div>\r\n                              <div class=\"col-4 col-md-2 col-lg-3 mt-2\">\r\n                                <el-tag\r\n                                  :disable-transitions=\"true\"\r\n                                  v-if=\"!order_pend.change_subtotal\"\r\n                                  size=\"medium\"\r\n                                >\r\n                                  <strong style=\"font-weight: 700\">\r\n                                    {{\r\n                                      parseFloat(\r\n                                        order_pend.price * order_pend.quantity\r\n                                      ).toFixed(2)\r\n                                    }}</strong\r\n                                  >\r\n                                </el-tag>\r\n                                <el-input\r\n                                  v-else\r\n                                  class=\"input-new-tag1\"\r\n                                  v-model=\"order_pend.newSubtotal\"\r\n                                  @input=\"justNumber(indexx)\"\r\n                                  placeholder=\"0.00\"\r\n                                  size=\"medium\"\r\n                                >\r\n                                </el-input>\r\n                                <template\r\n                                  v-if=\"configuration.edit_subtotal_box\"\r\n                                >\r\n                                  <el-tag\r\n                                    v-if=\"!order_pend.change_subtotal\"\r\n                                    role=\"button\"\r\n                                    size=\"medium\"\r\n                                    @click=\"changeSubtotal(indexx)\"\r\n                                  >\r\n                                    <i class=\"fas fa-edit text-primary\"></i>\r\n                                  </el-tag>\r\n                                  <el-tag\r\n                                    v-else\r\n                                    role=\"button\"\r\n                                    size=\"medium\"\r\n                                    @click=\"saveSubtotal(indexx)\"\r\n                                  >\r\n                                    <i class=\"fas fa-save text-primary\"></i>\r\n                                  </el-tag>\r\n                                </template>\r\n                              </div>\r\n                            </div>\r\n                            <div v-if=\"order_pend.food.item.series_enabled\">\r\n                              <template v-if=\"order_pend.series.length == 0\">\r\n                                <el-tag\r\n                                  style=\"margin-top: 5px\"\r\n                                  role=\"button\"\r\n                                  @click=\"showSeriesDialog(order_pend, indexx)\"\r\n                                  type=\"danger\"\r\n                                  >**Seleccione una serie\r\n                                </el-tag>\r\n                              </template>\r\n                              <template v-else>\r\n                                <div\r\n                                  v-for=\"(serie, idx) in order_pend.series\"\r\n                                  :key=\"idx\"\r\n                                  style=\"margin-top: 5px\"\r\n                                >\r\n                                  <el-tag\r\n                                    type=\"primary\"\r\n                                    closable\r\n                                    :disable-transitions=\"false\"\r\n                                    @close=\"deleteSerie(indexx, serie.id)\"\r\n                                  >\r\n                                    {{ serie.series }}\r\n                                  </el-tag>\r\n                                  <br />\r\n                                </div>\r\n                                <el-tag\r\n                                  style=\"margin-top: 5px\"\r\n                                  role=\"button\"\r\n                                  @click=\"showSeriesDialog(order_pend, indexx)\"\r\n                                  type=\"success\"\r\n                                  >Ver Series\r\n                                </el-tag>\r\n                              </template>\r\n                            </div>\r\n                            <div\r\n                              v-if=\"\r\n                                order_pend.food.item.lots_enabled &&\r\n                                !order_pend.food.item.series_enabled\r\n                              \"\r\n                            >\r\n                              <template v-if=\"order_pend.lotes.length == 0\">\r\n                                <el-tag\r\n                                  style=\"margin-top: 5px\"\r\n                                  role=\"button\"\r\n                                  @click=\"showLotesDialog\"\r\n                                  type=\"danger\"\r\n                                  >**Seleccione el lote</el-tag\r\n                                >\r\n                              </template>\r\n                              <template v-else>\r\n                                <div\r\n                                  v-for=\"(lot, idx) in order_pend.lotes\"\r\n                                  :key=\"idx\"\r\n                                  style=\"margin-top: 5px\"\r\n                                  v-show=\"lot.quantitySelected > 0\"\r\n                                >\r\n                                  <el-tooltip\r\n                                    :content=\"`Cant. en almacén: ${lot.quantity}`\"\r\n                                  >\r\n                                    <el-tag type=\"primary\">\r\n                                      {{ lot.code }}\r\n                                      <template\r\n                                        v-if=\"\r\n                                          order_pend.food.item.lots_group\r\n                                            .length > 1\r\n                                        \"\r\n                                      >\r\n                                        - Cant.\r\n                                        {{ lot.quantitySelected }}\r\n                                      </template>\r\n                                    </el-tag>\r\n                                  </el-tooltip>\r\n                                  <br />\r\n                                </div>\r\n                                <el-tag\r\n                                  v-if=\"\r\n                                    order_pend.food.item.lots_group.length > 1\r\n                                  \"\r\n                                  style=\"margin-top: 5px\"\r\n                                  role=\"button\"\r\n                                  @click=\"showLotesDialog(order_pend, indexx)\"\r\n                                  type=\"success\"\r\n                                  >Ver Lotes\r\n                                </el-tag>\r\n                              </template>\r\n                            </div>\r\n                            <div v-if=\"order_pend.observation\">\r\n                              <small>OBS: {{ order_pend.observation }}</small>\r\n                            </div>\r\n                          </div>\r\n                        </div>\r\n                        <hr />\r\n                      </div>\r\n                    </div>\r\n                    <div\r\n                      class=\"\r\n                        d-flex\r\n                        h-50\r\n                        justify-content-center\r\n                        align-items-center\r\n                      \"\r\n                      v-if=\"localOrden.length == 0 && !variation\"\r\n                    >\r\n                      <p class=\"font-weight-lighter\">Lista vacía.</p>\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </section>\r\n      </div>\r\n    </div>\r\n\r\n    <el-dialog\r\n      @close=\"closeLocalObservationDialog\"\r\n      :visible=\"dialogLocalObservation\"\r\n      append-to-body\r\n      title=\"Editando observación\"\r\n    >\r\n      <span>\r\n        <label class=\"control-label\"> Observación </label>\r\n        <el-input v-model=\"localObservation\"></el-input>\r\n      </span>\r\n      <span slot=\"footer\" class=\"dialog-footer\">\r\n        <button\r\n          class=\"btn btn-sm btn-secondary\"\r\n          @click=\"changeLocalObservation\"\r\n        >\r\n          Cambiar\r\n        </button>\r\n        <button\r\n          class=\"btn btn-sm btn-light\"\r\n          @click=\"closeLocalObservationDialog\"\r\n        >\r\n          Cerrar\r\n        </button>\r\n      </span>\r\n    </el-dialog>\r\n\r\n    <el-dialog\r\n      :visible=\"apart\"\r\n      :close-on-click-modal=\"false\"\r\n      :close-on-press-escape=\"false\"\r\n      title=\"Aparcar orden\"\r\n      @close=\"apart = false\"\r\n      width=\"20%\"\r\n    >\r\n      <div class=\"card p-2\">\r\n        <label class=\"control-label\">Datos Referenciales</label>\r\n        <el-input v-model=\"numberCustomerApart\" placeholder=\"Dni o Nombre\">\r\n        </el-input>\r\n\r\n        <div class=\"d-flex justify-content-end\">\r\n          <button class=\"btn btn-light m-1\" @click=\"apart = false\">\r\n            Cancelar\r\n          </button>\r\n\r\n          <button class=\"btn btn-primary m-1\" @click=\"pullApartOrden\">\r\n            Aparcar\r\n          </button>\r\n        </div>\r\n      </div>\r\n    </el-dialog>\r\n    <transfers-modal :showDialog.sync=\"showTransfersDialog\"></transfers-modal>\r\n    <show-lotes-product\r\n      :idx=\"currentIdx\"\r\n      :orden=\"ordenLot\"\r\n      :showDialog.sync=\"showLotes\"\r\n      @updateLotes=\"updateLotes\"\r\n    ></show-lotes-product>\r\n    <show-series-product\r\n      :limitQty=\"limitQty\"\r\n      :idx=\"currentIdx\"\r\n      :item=\"currentItem\"\r\n      :showDialog.sync=\"showSeries\"\r\n      :seriesSelected.sync=\"currentSeries\"\r\n      @updateSeries=\"updateSeries\"\r\n    >\r\n    </show-series-product>\r\n\r\n    <orden-pull-apart\r\n      @restoreToLocalOrdens=\"restoreToLocalOrdens\"\r\n      :showPullApart.sync=\"listApart\"\r\n      :ordenInBox.sync=\"ordenInBox\"\r\n    >\r\n    </orden-pull-apart>\r\n    <table-ordens-pending\r\n      :areas=\"areas\"\r\n      :showPendingOrdens.sync=\"showPendingOrdens\"\r\n    >\r\n    </table-ordens-pending>\r\n    <cash-form\r\n      :showDialog.sync=\"showDialogCash\"\r\n      :recordId=\"cash_id\"\r\n      :fromBox=\"true\"\r\n      @updateCashId=\"updateCashId\"\r\n    ></cash-form>\r\n    <close-cash\r\n      :recordId.sync=\"cash_id\"\r\n      :showDialogClose.sync=\"showDialogClose\"\r\n      :fromBox=\"true\"\r\n      @updateCashId=\"updateCashId\"\r\n    >\r\n    </close-cash>\r\n    <expenses-incomes\r\n      :showDialog.sync=\"showExpensesIncomes\"\r\n      :company=\"company\"\r\n      :cash_id=\"cash_id\"\r\n    >\r\n    </expenses-incomes>\r\n    <observation-form\r\n      :current=\"current\"\r\n      :observations.sync=\"tags\"\r\n      :showDialog.sync=\"showObservations\"\r\n      @addObservation=\"addObservation\"\r\n    >\r\n    </observation-form>\r\n        <quotation-form\r\n            :showDialog.sync=\"showQuotationForm\"\r\n            :items=\"localOrden\"\r\n            :customers=\"customers\"\r\n            @limpiarForm=\"limpiarForm\"\r\n            :cash_id=\"cash_id\"\r\n        >\r\n        </quotation-form>\r\n\r\n        <credit-form\r\n            :showDialog.sync=\"showCreditForm\"\r\n            :items=\"localOrden\"\r\n            :customers=\"customers\"\r\n            @limpiarForm=\"limpiarForm\"\r\n            :cash_id=\"cash_id\"\r\n            :all_series.sync=\"all_series\"\r\n            :establishments=\"establishments\"\r\n        >\r\n        </credit-form>\r\n    <el-dialog\r\n      :visible.sync=\"showChangeDescriptionVariation\"\r\n      title=\"Cambiar descripción\"\r\n      @close=\"showChangeDescriptionVariation = false\"\r\n    >\r\n      <div class=\"card p-3\">\r\n        <el-input placeholder=\"Nueva descripción\" v-model=\"descriptionTemp\">\r\n        </el-input\r\n        ><br />\r\n        <div class=\"d-flex justify-content-end\">\r\n          <el-button type=\"primary\" @click=\"changeDescription\">\r\n            Cambiar\r\n          </el-button>\r\n          <el-button @click=\"showChangeDescriptionVariation = false\">\r\n            Cerrar\r\n          </el-button>\r\n        </div>\r\n      </div>\r\n    </el-dialog>\r\n  </div>\r\n</template>\r\n<style>\r\n.el-input-group__prepend {\r\n  padding-left: 6px !important;\r\n  padding-right: 6px !important;\r\n}\r\n\r\n.custom_input .el-input__inner {\r\n  padding: 0 5px !important;\r\n}\r\n\r\n.el-tag + .el-tag {\r\n  margin-left: 10px;\r\n}\r\n\r\n.button-new-tag {\r\n  margin-left: 10px;\r\n  height: 32px;\r\n  line-height: 30px;\r\n  padding-top: 0;\r\n  padding-bottom: 0;\r\n}\r\n\r\n.input-new-tag1 {\r\n  width: 70px;\r\n  margin-left: 10px;\r\n  vertical-align: bottom;\r\n}\r\n\r\n.input-new-tag1 .el-input__inner {\r\n  height: 30px !important;\r\n}\r\n</style>\r\n<script>\r\nimport Quotation_modal from \"./quotation_modal.vue\";\r\n//const PaymentForm =() => import('./partials/payment.vue')\r\n/* import CashForm from \"../../cash/form.vue\";\r\nimport CloseCash from \"../../cash/closecash.vue\";\r\nimport OrdenPullApart from \"./ordens_pull_apart.vue\";\r\nimport TableOrdensPending from \"./list_pending_ordens.vue\";\r\nimport ObservationForm from \"../../partials/observation_form.vue\"; */\r\nconst QuotationForm = () => import(\"./quotation_modal.vue\");\r\nconst CreditForm = () => import(\"./credit_modal.vue\");\r\nconst CashForm = () => import(\"../../cash/form.vue\");\r\nconst CloseCash = () => import(\"../../cash/closecash.vue\");\r\nconst OrdenPullApart = () => import(\"./ordens_pull_apart.vue\");\r\nconst TableOrdensPending = () => import(\"./list_pending_ordens.vue\");\r\nconst ObservationForm = () => import(\"../../partials/observation_form.vue\");\r\nconst ExpensesIncomes = () => import(\"../partials/expenses_incomes.vue\");\r\nconst ShowSeriesProduct = () => import(\"../partials/show_series_product.vue\");\r\nconst ShowLotesProduct = () => import(\"../partials/show_lotes_product.vue\");\r\nconst TransfersModal = () => import(\"../partials/transfer_modal.vue\");\r\nexport default {\r\n  components: {\r\n    CreditForm,\r\n    CashForm,\r\n    CloseCash,\r\n    TableOrdensPending,\r\n    OrdenPullApart,\r\n    ObservationForm,\r\n    ExpensesIncomes,\r\n    ShowSeriesProduct,\r\n    ShowLotesProduct,\r\n    TransfersModal,\r\n    QuotationForm,\r\n  },\r\n  props: [\r\n        \"all_series\",\r\n    \"areas\",\r\n        \"customers\",\r\n    \"company\",\r\n    \"customer_variation\",\r\n    \"variationShow\",\r\n    \"establishments\",\r\n    \"itemDefault\",\r\n    \"ordensPending\",\r\n    \"area_id\",\r\n    \"blockCart\",\r\n    \"localOrden\",\r\n    \"configuration\",\r\n    \"ordens\",\r\n    \"total2\",\r\n    \"clientTableData\",\r\n    \"isCreatingOrden\",\r\n    \"ordenId\",\r\n    \"cash_id\",\r\n  ],\r\n\r\n  data() {\r\n    return {\r\n            showCreditForm: false,\r\n            showQuotationForm: false,\r\n      limitQty: 0,\r\n      showTransfersDialog: false,\r\n      descriptionTemp: null,\r\n      showChangeDescriptionVariation: false,\r\n      variation: false,\r\n      showObservations: false,\r\n      boxOperation: \"Abrir\",\r\n      showDialogCash: false,\r\n      tags: [],\r\n      showSeries: false,\r\n      current: null,\r\n      showDialogClose: false,\r\n      showPendingOrdens: false,\r\n      ordenLoading: false,\r\n      listApart: false,\r\n      apart: false,\r\n      numberCustomerApart: null,\r\n      ordenInBox: [],\r\n      pin: \"\",\r\n      totalOrdenItems: 0.0,\r\n      total: 0.0,\r\n      disableSend: false,\r\n      totalOrden: 0.0,\r\n      loading: false,\r\n      commands_fisico: \"\",\r\n      AllSelected: false,\r\n      showDialogPing: false,\r\n      dialogLocalObservation: false,\r\n      currentLocalOrden: null,\r\n      localObservation: null,\r\n      dialogObservation: false,\r\n      observation: null,\r\n      loadingObservation: false,\r\n      currentOrden: null,\r\n      form_ped: {},\r\n      to_carry: false,\r\n      optionsMenu: [],\r\n      foodDefault: null,\r\n      showExpensesIncomes: false,\r\n      showLotes: false,\r\n      ordenLot: null,\r\n      currentIdx: null,\r\n      currentItem: null,\r\n      currentSeries: [],\r\n      screenWidth: 0,\r\n      printing: false,\r\n      foodDefaults: [],\r\n      currentFoodDefault: null,\r\n    };\r\n  },\r\n\r\n  watch: {\r\n    variationShow(variat, _) {\r\n      if (this.variation && !variat) {\r\n        this.variation = false;\r\n      }\r\n    },\r\n    itemDefault(newItem, _) {\r\n      this.foodDefault = this.itemDefault;\r\n      this.foodDefault.quantity = 1;\r\n      this.foodDefault.sale_unit_price = Number(\r\n        this.foodDefault.sale_unit_price\r\n      );\r\n      this.foodDefaults = [{ ...this.foodDefault }];\r\n    },\r\n    cash_id(newCash, _) {\r\n      this.boxOperation = newCash ? \"Cerrar\" : \"Abrir\";\r\n      this.optionsMenu[2].title = [this.boxOperation, \" Caja\"];\r\n    },\r\n    ordens(newOrdens, _) {\r\n      this.calculateTotal(newOrdens);\r\n    },\r\n    localOrden(newOrdens, _) {\r\n      this.calculateTotal(this.ordens);\r\n    },\r\n  },\r\n  mounted() {\r\n    this.screenWidth = window.innerWidth;\r\n    window.addEventListener(\"resize\", this.handleResize);\r\n    this.foodDefault = this.itemDefault;\r\n    this.boxOperation = this.cash_id ? \"Cerrar\" : \"Abrir\";\r\n\r\n    this.optionsMenu = [\r\n      {\r\n        id: 1,\r\n        title: [\"Configuración\"],\r\n        icon: \"fas fa-cogs\",\r\n        visible: false,\r\n      },\r\n      {\r\n        id: 2,\r\n        title: [\"Recibir \", \"mercaderia\"],\r\n        icon: \"fas fa-people-carry\",\r\n        visible: !this.configuration.college,\r\n      },\r\n      {\r\n        id: 3,\r\n        title: [this.boxOperation, \" Caja\"],\r\n        icon: \"fas fa-cash-register\",\r\n        visible: true,\r\n      },\r\n      {\r\n        id: 7,\r\n        title: [\"Ingresos/\", \"/Gastos\"],\r\n        icon: \"fas fa-money-bill-wave-alt\",\r\n        visible: true,\r\n      },\r\n      {\r\n        id: 4,\r\n        title: [\"Aparcado\"],\r\n        icon: \"fas fa-cart-arrow-down\",\r\n        visible: !this.configuration.college,\r\n      },\r\n\r\n      {\r\n        id: 5,\r\n        title: [\"Ordenes\"],\r\n        icon: \"fas fa-hourglass\",\r\n        visible: this.configuration.restaurant && !this.configuration.college,\r\n      },\r\n    ];\r\n    let ordens = [];\r\n    let ordensSave = localStorage.ordens;\r\n    if (ordensSave) {\r\n      ordens = JSON.parse(ordensSave);\r\n    }\r\n    this.ordenInBox = ordens;\r\n  },\r\n  async created() {\r\n    let printing = localStorage.getItem(\"cajaPrint\");\r\n\r\n    this.printing = printing == 1;\r\n    qz.security.setCertificatePromise((resolve, reject) => {\r\n      this.$http\r\n        .get(\"/api/qz/crt/override\", {\r\n          responseType: \"text\",\r\n        })\r\n        .then((response) => {\r\n          resolve(response.data);\r\n        })\r\n        .catch((error) => {\r\n          reject(error.data);\r\n        });\r\n    });\r\n    qz.security.setSignaturePromise((toSign) => {\r\n      return (resolve, reject) => {\r\n        this.$http\r\n          .post(\"/api/qz/signing\", {\r\n            request: toSign,\r\n          })\r\n          .then((response) => {\r\n            resolve(response.data);\r\n          })\r\n          .catch((error) => {\r\n            reject(error.data);\r\n          });\r\n      };\r\n    });\r\n\r\n    await this.getTags();\r\n  },\r\n  methods: {\r\n    deleteDefaultFood(index) {\r\n      this.foodDefaults = this.foodDefaults.filter((_, i) => i != index);\r\n    },\r\n    addVariation() {\r\n      let foodDefault = { ...this.itemDefault };\r\n      foodDefault.description =\r\n        foodDefault.description + \" \" + Number(this.foodDefaults.length + 1);\r\n      this.foodDefaults = [...this.foodDefaults, foodDefault];\r\n\r\n    },\r\n        openCredit() {\r\n            this.showCreditForm = true;\r\n        },\r\n        openQuotation() {\r\n            this.showQuotationForm = true;\r\n        },\r\n    savePrint() {\r\n      localStorage.setItem(\"cajaPrint\", this.printing ? 1 : 0);\r\n      this.$toast.success(\"Configuración guardada\");\r\n    },\r\n    handleResize() {\r\n      this.screenWidth = window.innerWidth;\r\n    },\r\n    showTransfers() {\r\n      this.showTransfersDialog = true;\r\n    },\r\n    deleteSerie(index, serie_id) {\r\n      let ordens = [...this.localOrden];\r\n\r\n      ordens[index].series = ordens[index].series.filter(\r\n        (s) => s.id != serie_id\r\n      );\r\n      ordens[index].quantity = ordens[index].series.length;\r\n      this.$emit(\"update:localOrden\", ordens);\r\n    },\r\n    updateSeries(idx, series) {\r\n      let ordens = [...this.localOrden];\r\n      ordens[idx].series = series;\r\n      if (this.limitQty) {\r\n        ordens[idx].quantity = series.length / this.limitQty;\r\n      } else {\r\n        ordens[idx].quantity = series.length;\r\n      }\r\n\r\n      this.$emit(\"update:localOrden\", ordens);\r\n    },\r\n    updateLotes(idx, lotes) {\r\n      let ordens = [...this.localOrden];\r\n      ordens[idx].lotes = lotes;\r\n      ordens[idx].quantity = lotes.reduce(\r\n        (a, b) => a + Number(b.quantitySelected),\r\n        0\r\n      );\r\n      this.$emit(\"update:localOrden\", ordens);\r\n    },\r\n    showLotesDialog(orden, index) {\r\n      this.ordenLot = orden;\r\n      this.currentIdx = index;\r\n      this.showLotes = true;\r\n    },\r\n    showSeriesDialog(orden, index = null) {\r\n      this.limitQty = orden.type_quantity ?? 0;\r\n\r\n      let ordens = this.localOrden.filter((l) => l.id == orden.id);\r\n      if (ordens.length == 1) {\r\n        let [currentOrden] = ordens;\r\n        let series = currentOrden.series.map((s) => ({\r\n          ...s,\r\n          disabled: false,\r\n        }));\r\n        this.currentSeries = series;\r\n      } else {\r\n        let series = [];\r\n        for (let i = 0; i < ordens.length; i++) {\r\n          let currentOrden = ordens[i];\r\n          series = [\r\n            ...series,\r\n            ...currentOrden.series.map((s) => ({\r\n              ...s,\r\n              disabled: orden.type_id != currentOrden.type_id,\r\n            })),\r\n          ];\r\n        }\r\n        this.currentSeries = series;\r\n      }\r\n      this.currentItem = orden.food.item;\r\n      // this.currentSeries = orden.series;\r\n\r\n      this.currentIdx = index;\r\n      this.showSeries = true;\r\n    },\r\n    justNumber(indexx) {\r\n      this.localOrden[indexx].newSubtotal = this.localOrden[\r\n        indexx\r\n      ].newSubtotal.replace(/[^0-9.]/g, \"\");\r\n    },\r\n    updateDefaultFoodQty(bool, idx) {\r\n      let foodDefault = this.foodDefaults[idx];\r\n      if (bool) {\r\n        foodDefault.quantity += 1;\r\n      } else {\r\n        if (foodDefault.quantity > 1) {\r\n          foodDefault.quantity -= 1;\r\n        }\r\n      }\r\n\r\n      this.$forceUpdate();\r\n    },\r\n    showChangeDescription(idx) {\r\n      this.descriptionTemp = null;\r\n      this.currentFoodDefault = idx;\r\n      this.showChangeDescriptionVariation = true;\r\n    },\r\n    changeDescription() {\r\n      let foodDefault = this.foodDefaults[this.currentFoodDefault];\r\n      foodDefault.description = this.descriptionTemp;\r\n      this.showChangeDescriptionVariation = false;\r\n    },\r\n    changeVariation() {\r\n      if (this.customer_variation == null) {\r\n        this.variation = false;\r\n\r\n        return this.$toast.error(\"Clientes modificado no creado\");\r\n      }\r\n      if (this.itemDefault == null) {\r\n        this.variation = false;\r\n\r\n        return this.$toast.error(\"Producto para variación no seleccionado\");\r\n      }\r\n\r\n      this.foodDefaults = [this.foodDefault];\r\n    },\r\n    saveSubtotal(idx) {\r\n      let ordensModified = [...this.localOrden];\r\n      let currentOrden = ordensModified[idx];\r\n      let sub = Number(currentOrden.newSubtotal);\r\n      if (isNaN(sub) || sub <= 0) {\r\n        ordensModified[idx].change_subtotal = false;\r\n        ordensModified[idx].series = [];\r\n        ordensModified[idx].lotes = [];\r\n        ordensModified[idx].newSubtotal = null;\r\n        this.$emit(\"update:localOrden\", ordensModified);\r\n        this.$toast.error(\"Subtotal no válido\");\r\n        return;\r\n      }\r\n      let qty = Number(currentOrden.quantity);\r\n      let price = sub / qty;\r\n      ordensModified[idx].price = price;\r\n      ordensModified[idx].change_subtotal = false;\r\n      ordensModified[idx].series = [];\r\n      ordensModified[idx].lotes = [];\r\n      ordensModified[idx].newSubtotal = null;\r\n      this.$emit(\"update:localOrden\", ordensModified);\r\n      this.calculateTotal();\r\n      this.$toast.success(\"Subtotal actualizado\");\r\n    },\r\n    changeSubtotal(idx) {\r\n      let ordensModified = [...this.localOrden];\r\n      ordensModified[idx].change_subtotal =\r\n        !ordensModified[idx].change_subtotal;\r\n      this.$emit(\"update:localOrden\", ordensModified);\r\n    },\r\n    addObservation(obs) {\r\n      let ordensModified = [...this.localOrden];\r\n      ordensModified[this.currentLocalOrden].observation = obs;\r\n      this.$emit(\"update:localOrden\", ordensModified);\r\n    },\r\n    async getTags() {\r\n      const response = await this.$http(\"../observations/records\");\r\n      if (response.status == 200) {\r\n        const { data } = response;\r\n        this.tags = data;\r\n      }\r\n    },\r\n    async updateCashId(id) {\r\n      this.$emit(\"update:cash_id\", id);\r\n    },\r\n    async cancelGeneralOrden(id) {\r\n      try {\r\n        let res = await this.$confirm(\r\n          \"Desea cancelar toda la orden?\",\r\n          \"Cancelar\",\r\n          {\r\n            confirmButtonText: \"Ok\",\r\n            cancelButtonText: \"Cancelar\",\r\n            type: \"warning\",\r\n          }\r\n        );\r\n        if (res) {\r\n          this.loading = true;\r\n\r\n          let form = {\r\n            id,\r\n          };\r\n          const response = await this.$http.post(\"cancel-orden\", form);\r\n          if (response.status == 200) {\r\n            const { message } = response.data;\r\n            this.$toast.success(message);\r\n            this.$eventHub.$emit(\"reloadData\");\r\n            this.$emit(\"ordenDeleted\");\r\n          }\r\n        }\r\n      } catch (e) {\r\n        if (e != \"cancel\") {\r\n          console.log(e);\r\n          this.$toast.error(\"Ocurrió un error\");\r\n        }\r\n      } finally {\r\n        this.loading = false;\r\n      }\r\n    },\r\n    allToCarry() {\r\n      if (this.localOrden.length == 0) return;\r\n      let ord = [...this.localOrden];\r\n      ord = ord.map((o) => {\r\n        let {\r\n          food: {\r\n            item: { delivery_cost },\r\n          },\r\n        } = o;\r\n        let delivery = Number(delivery_cost);\r\n        let factor = this.to_carry ? 1 : -1;\r\n        let price = Number(o.price) + delivery * factor;\r\n\r\n        return {\r\n          ...o,\r\n          to_carry: this.to_carry,\r\n          price,\r\n        };\r\n      });\r\n      this.$emit(\"update:localOrden\", ord);\r\n    },\r\n    toCarry(idx) {\r\n      let ord = [...this.localOrden];\r\n      let {\r\n        food: {\r\n          item: { delivery_cost },\r\n        },\r\n      } = ord[idx];\r\n      ord[idx].to_carry = !ord[idx].to_carry;\r\n      let delivery = Number(delivery_cost);\r\n      let factor = ord[idx].to_carry ? 1 : -1;\r\n      ord[idx].price = Number(ord[idx].price) + delivery * factor;\r\n\r\n      this.$emit(\"update:localOrden\", ord);\r\n    },\r\n    verifyStock(orden, idx) {\r\n      if (this.configuration.sales_stock) {\r\n        let current_orden = this.localOrden.filter((o) => o.id == orden.id);\r\n        let qty = current_orden.reduce((a, b) => a + Number(b.quantity), 0);\r\n        let stock = 0;\r\n        if (current_orden.length == 1 && current_orden[0].lotes.length == 1) {\r\n          let [orden] = current_orden;\r\n          let [lote] = orden.lotes;\r\n          stock = lote.quantity;\r\n        } else {\r\n          stock = Number(current_orden[0].food.item.stock);\r\n        }\r\n        if (qty > stock) {\r\n          this.$toast.warning(\"Sobrepaso el stock\");\r\n          let localOrden_quantity = this.localOrden;\r\n          localOrden_quantity[idx].quantity = 1;\r\n          return;\r\n        }\r\n        if (current_orden.length == 1) {\r\n          let [orden] = current_orden;\r\n          if (orden.lotes.length == 1) {\r\n            orden.lotes[0].quantitySelected = this.localOrden[idx].quantity;\r\n          }\r\n        }\r\n      }\r\n\r\n      this.calculateTotal();\r\n    },\r\n    showOrdensPending() {\r\n      this.showPendingOrdens = true;\r\n    },\r\n\r\n    validStock(orden, quantity = 1) {\r\n      let qty = this.localOrden\r\n        .filter((o) => o.id == orden.id)\r\n        .reduce((a, b) => a + Number(b.quantity), 0);\r\n      if (orden.type_id) {\r\n        qty += orden.type_quantity;\r\n      } else {\r\n        qty += quantity;\r\n      }\r\n      let stock = Number(orden.food.item.stock);\r\n\r\n      if (this.configuration.sales_stock == true) {\r\n        if (qty > stock) {\r\n          return true;\r\n        }\r\n      }\r\n      return false;\r\n    },\r\n    async printOrden() {\r\n      this.ordenLoading = true;\r\n      try {\r\n        await this.printTicket(this.clientTableData.orden_id);\r\n      } catch (e) {\r\n        this.$toast.error(\"No se pudo imprimir\");\r\n      } finally {\r\n        this.ordenLoading = false;\r\n      }\r\n    },\r\n    async sendOrden() {\r\n      if (this.localOrden.length == 0 && !this.variation) {\r\n        this.$toast.warning(\"Orden sin productos\");\r\n        return;\r\n      }\r\n      let orden = {\r\n        status_orden_id: 1,\r\n        table_id: this.clientTableData.table_id,\r\n        to_carry: this.to_carry,\r\n      };\r\n\r\n      this.ordenLoading = true;\r\n      try {\r\n        const responses = await this.$http.post(\r\n          \"/restaurant/worker/send-orden\",\r\n          {\r\n            id: this.clientTableData.orden_id,\r\n            ref: this.clientTableData.ref,\r\n            items: this.localOrden,\r\n            caja: true,\r\n            printing: true,\r\n            saleDirect: false,\r\n            orden,\r\n          }\r\n        );\r\n        let ordenId = responses.data.id;\r\n        this.ordenLoading = false;\r\n        if (responses.status != 200) {\r\n          this.$toast.warning(\"Ocurrió un error\");\r\n\r\n          return;\r\n        }\r\n        this.to_carry = false;\r\n        this.$emit(\"cancelOrden\");\r\n        this.$emit(\"update:isCreatingOrden\", false);\r\n        let msg = \"\";\r\n        if (this.clientTableData.orden_id) {\r\n          msg = `Se agregaron los pedidos a la orden ${ordenId}`;\r\n        } else {\r\n          msg = `La orden ${ordenId} fue creada.`;\r\n        }\r\n        this.$toast.success(msg);\r\n      } catch (e) {\r\n        this.ordenLoading = false;\r\n        //no jala el clientdata tble - ref // lo guarda con el id mesa caja\r\n        this.$toast.error(\"Ocurrió un error\");\r\n      }\r\n    },\r\n    directSale() {\r\n      this.$emit(\"update:clientTableData\", {});\r\n      this.$emit(\"update:localOrden\", []);\r\n      this.$emit(\"update:ordens\", []);\r\n      this.$emit(\"update:blockCart\", false);\r\n      this.$emit(\"update:isCreatingOrden\", false);\r\n      //ordenId\r\n      this.$emit(\"update:idOrden\", null);\r\n      this.$emit(\"resetOrden\");\r\n    },\r\n    restoreToLocalOrdens(ordens) {\r\n      this.$emit(\"update:localOrden\", ordens);\r\n    },\r\n    trigerFunction(id) {\r\n      switch (id) {\r\n        case 7:\r\n          if (!this.cash_id) {\r\n            this.$toast.error(\"Abra una caja\");\r\n          } else {\r\n            this.showExpensesIncomes = true;\r\n          }\r\n          break;\r\n        case 2:\r\n          this.showTransfers();\r\n          break;\r\n        case 3:\r\n          if (this.cash_id) {\r\n            this.showDialogClose = true;\r\n          } else {\r\n            this.showDialogCash = true;\r\n          }\r\n          break;\r\n        case 5:\r\n          this.showOrdensPending();\r\n          break;\r\n        case 4:\r\n          if (this.ordenInBox.length > 0) {\r\n            this.listApart = true;\r\n          } else {\r\n            this.$toast.warning(\"Sin ventas apartacadas.\");\r\n          }\r\n          break;\r\n\r\n        default:\r\n          //naa\r\n          break;\r\n      }\r\n    },\r\n        limpiarForm() {\r\n            this.$emit(\"limpiarForm\");\r\n        },\r\n    openApart() {\r\n      if (this.localOrden.length == 0) {\r\n        this.$toast.error(\"Sin ordenes pendientes\");\r\n        return;\r\n      }\r\n      this.apart = true;\r\n    },\r\n    pullApartOrden() {\r\n      if (!this.numberCustomerApart && this.numberCustomerApart.length <= 1) {\r\n        this.$toast.error(\"Documento o referencia inválida\");\r\n        return;\r\n      } else if (this.ordenInBox.length == 3) {\r\n        this.$toast.error(\"Limite excedido. \");\r\n        return;\r\n      } else if (\r\n        this.ordenInBox.some(\r\n          (f) => f.ref.toLowerCase() == this.numberCustomerApart.toLowerCase()\r\n        )\r\n      ) {\r\n        this.$toast.error(\"La referencia ya existe\");\r\n        return;\r\n      } else {\r\n        this.ordenInBox.push({\r\n          ref: this.numberCustomerApart,\r\n          ordens: this.localOrden,\r\n        });\r\n\r\n        localStorage.ordens = JSON.stringify(this.ordenInBox);\r\n        this.numberCustomerApart = undefined;\r\n        this.apart = false;\r\n        this.$emit(\"cancelOrden\");\r\n        this.$toast.success(\"Orden aparcada\");\r\n      }\r\n    },\r\n    async cancelOrden() {\r\n      let res = await this.$confirm(\"Desea cancelar este pedido?\", \"Cancelar\", {\r\n        confirmButtonText: \"Ok\",\r\n        cancelButtonText: \"Cancelar\",\r\n        type: \"warning\",\r\n      });\r\n      if (res) {\r\n        this.$emit(\"cancelOrden\");\r\n      }\r\n    },\r\n    addNumberPin(number) {\r\n      if (this.pin.length >= 4) {\r\n        return;\r\n      }\r\n      this.pin += number.toString();\r\n    },\r\n    close() {\r\n      this.$emit(\"update:localOrden\", []);\r\n    },\r\n    update_price(index, sale_unit_price) {\r\n      let localOrden_update = this.localOrden;\r\n      localOrden_update[index].food.sale_unit_price = sale_unit_price;\r\n      this.$emit(\"update:localOrden\", localOrden_update);\r\n      this.calculateTotal();\r\n    },\r\n    sumar_orden(index) {\r\n      if (this.validStock(this.localOrden[index])) {\r\n        this.$toast.warning(\"Limite de stock alcanzado\");\r\n        return;\r\n      }\r\n      let localOrden_quantity = this.localOrden;\r\n      if (this.localOrden[index].type_id) {\r\n        localOrden_quantity[index].quantity =\r\n          Number(localOrden_quantity[index].quantity) + 1;\r\n        // localOrden_quantity[index].quantity =\r\n        //     Number(localOrden_quantity[index].quantity) +\r\n        //     Number(localOrden_quantity[index].type_quantity);\r\n      } else {\r\n        localOrden_quantity[index].quantity =\r\n          Number(localOrden_quantity[index].quantity) + 1;\r\n      }\r\n\r\n      this.$emit(\"update:localOrden\", localOrden_quantity);\r\n      this.calculateTotal();\r\n    },\r\n    restar_orden(index) {\r\n      let localOrden_quantity = this.localOrden;\r\n      let min = 1;\r\n      if (this.localOrden[index].type_id) {\r\n        min = Number(localOrden_quantity[index].type_quantity);\r\n      }\r\n      let quantity = localOrden_quantity[index].quantity * min;\r\n      if (quantity > min) {\r\n        // if (localOrden_quantity[index].quantity > min) {\r\n        if (this.localOrden[index].type_id) {\r\n          // localOrden_quantity[index].quantity =\r\n          //     Number(localOrden_quantity[index].quantity) -\r\n          //     Number(localOrden_quantity[index].type_quantity);\r\n          localOrden_quantity[index].quantity =\r\n            Number(localOrden_quantity[index].quantity) - 1;\r\n        } else {\r\n          localOrden_quantity[index].quantity =\r\n            Number(localOrden_quantity[index].quantity) - 1;\r\n        }\r\n\r\n        this.$emit(\"update:localOrden\", localOrden_quantity);\r\n        this.calculateTotal();\r\n      } else {\r\n        this.$toast.warning(\"Mínimo permitido\");\r\n      }\r\n    },\r\n    async printTicket(id) {\r\n      try {\r\n        const response = await this.$http.get(\r\n          `/restaurant/worker/record/${id}`\r\n        );\r\n        let url = response.data.print;\r\n\r\n        let config = qz.configs.create(response.data.printer, {\r\n          scaleContent: false,\r\n        });\r\n        if (!qz.websocket.isActive()) {\r\n          await qz.websocket.connect(config);\r\n        }\r\n        let data = [\r\n          {\r\n            type: \"pdf\",\r\n            format: \"file\",\r\n            data: url,\r\n          },\r\n        ];\r\n        qz.print(config, data).catch((e) => {\r\n          this.$toast.error(e.message);\r\n        });\r\n\r\n        //this.$toast.success(\"se esta imprimiendo el comprobante con exito\");\r\n        // qz.websocket.disconnect()\r\n      } catch (e) {\r\n        this.$toast.error(e.message);\r\n      }\r\n    },\r\n\r\n    view_orders() {\r\n      $(\".style-switcher\")\r\n        .animate(\r\n          {\r\n            right: \"0\",\r\n          },\r\n          300\r\n        )\r\n        .addClass(\"active\");\r\n    },\r\n\r\n    closeDialog(ordenId = null) {\r\n      let ordenToAdd = [...this.localOrden];\r\n      ordenToAdd = ordenToAdd.map((o) => ({\r\n        status_orden_id: 1,\r\n        food: {\r\n          description: o.food.description,\r\n          price: o.food.price,\r\n        },\r\n        observations: o.observation,\r\n      }));\r\n      // let allOrdens = [...ordenToAdd, ...this.ordens];\r\n      this.$emit(\"updateOrdens\", ordenId);\r\n      this.$emit(\"listtables\");\r\n      // this.$emit(\"update:ordens\", allOrdens);\r\n      this.$emit(\"update:localOrden\", []);\r\n      this.$eventHub.$emit(\"reloadData\");\r\n      this.totalOrdenItems = 0.0;\r\n      this.total = 0.0;\r\n      this.totalOrden = 0.0;\r\n    },\r\n    clear_command() {\r\n      this.commands_fisico = null;\r\n    },\r\n    checkIsExistSerie() {\r\n      let hasError = false;\r\n      for (let ord of this.localOrden) {\r\n        let { series_enabled } = ord.food.item;\r\n\r\n        if (series_enabled && ord.series.length == 0) {\r\n          hasError = true;\r\n          break;\r\n        }\r\n      }\r\n      return hasError;\r\n    },\r\n    async payOrden() {\r\n      if (this.checkIsExistSerie()) {\r\n        this.$toast.error(\"Producto sin serie seleccionada\");\r\n        return;\r\n      }\r\n      if (!this.cash_id) {\r\n        this.$toast.error(\"No tiene una caja abierta\");\r\n        return;\r\n      }\r\n      if (this.clientTableData.table) {\r\n        if (this.ordens.length == 0) {\r\n          this.$toast.warning(\"Orden sin productos\");\r\n          return;\r\n        }\r\n      } else {\r\n        if (this.localOrden.length == 0 && !this.variation) {\r\n          this.$toast.warning(\"Orden sin productos\");\r\n          return;\r\n        }\r\n      }\r\n\r\n      this.disableSend = true;\r\n      let form_submit = {\r\n        id: null,\r\n        caja: true,\r\n        printDocument: this.printing,\r\n        printing: this.configuration.print_commands,\r\n        commands_fisico: this.commands_fisico,\r\n        print_kitchen: this.configuration.print_kitchen,\r\n        to_carry: this.to_carry,\r\n        orden: {\r\n          table_id: 1,\r\n          status_orden_id: 1,\r\n        },\r\n        //enviar las ordenes a cobrar\r\n        //  items: this.ordens,\r\n        // items: this.localOrden,\r\n        pin: null,\r\n      };\r\n      if (this.clientTableData.table) {\r\n        form_submit.items = this.ordens;\r\n      } else {\r\n        form_submit.items = this.localOrden;\r\n      }\r\n      this.loading = true;\r\n      // const responses = await this.$http.post(\r\n      //     \"/restaurant/worker/send-orden\",\r\n      //     form_submit\r\n      // );\r\n\r\n      this.commands_fisico = \"\";\r\n      this.to_carry = false;\r\n      //    let IdOrdensend = responses.data.id;\r\n      //    if (responses.data.success == true) {\r\n\r\n      this.loading = false;\r\n      // this.$toast.success(responses.data.message);\r\n      this.disableSend = false;\r\n      //      document.querySelector(\"#close_offcanvas\").click();\r\n      // } else {\r\n      //     this.loading = false;\r\n      //     this.$toast.error(responses.data.message);\r\n      // }\r\n      if (this.variation) {\r\n        form_submit.variationItems = this.foodDefaults;\r\n      }\r\n      this.loading = false;\r\n      this.disableSend = false;\r\n\r\n      if (this.variation) {\r\n        this.$emit(\"paymentsOrden\", form_submit, this.foodDefaults);\r\n      } else {\r\n        this.$emit(\"paymentsOrden\", form_submit);\r\n      }\r\n    },\r\n    formatUrlImage(url) {\r\n      if (!url) return;\r\n      let formated = \"storage/uploads/items/\" + url;\r\n      return `/${formated}`;\r\n    },\r\n    async cancelGeneralOrden() {\r\n      this.loading = true;\r\n      try {\r\n        let res = await this.$confirm(\r\n          \"Desea cancelar toda la orden?\",\r\n          \"Cancelar\",\r\n          {\r\n            confirmButtonText: \"Ok\",\r\n            cancelButtonText: \"Cancelar\",\r\n            type: \"warning\",\r\n          }\r\n        );\r\n        if (res) {\r\n          let form = {\r\n            id: this.ordens[0].orden_id,\r\n          };\r\n          const response = await this.$http.post(\"cancel-orden\", form);\r\n          if (response.status == 200) {\r\n            const { message } = response.data;\r\n            this.$toast.success(message);\r\n            this.$eventHub.$emit(\"reloadData\");\r\n            this.$emit(\"ordenDeleted\");\r\n            this.directSale();\r\n          }\r\n        }\r\n      } catch (e) {\r\n        if (e != \"cancel\") {\r\n          console.log(e);\r\n          this.$toast.error(\"Ocurrió un error\");\r\n        }\r\n      }\r\n      this.loading = false;\r\n    },\r\n    calculateTotal(w = null) {\r\n      this.totalOrdenItems = 0.0;\r\n      this.total = 0.0;\r\n      this.totalOrden = 0.0;\r\n      let OrdenPen = 0;\r\n      let OrdenPenAtendidos = 0;\r\n      let nTotal_poratendidos = _.forEach(this.localOrden, function (value) {\r\n        OrdenPen = parseFloat(OrdenPen) + value.quantity * value.price;\r\n      });\r\n      this.totalOrden = _.round(OrdenPen, 2);\r\n      let nTotal_atendidos = _.forEach(this.ordens, function (values) {\r\n        OrdenPenAtendidos =\r\n          parseFloat(OrdenPenAtendidos) + values.quantity * values.price;\r\n      });\r\n      this.totalOrdenItems = _.round(OrdenPenAtendidos, 2);\r\n      // this.total = this.totalOrden + this.totalOrdenItems;\r\n      this.total = _.round(this.totalOrden, 2);\r\n      this.$emit(\"total_salcancelOrdenaes\", this.total);\r\n    },\r\n    deleteFood(idx) {\r\n      this.$emit(\"deletedFood\", idx);\r\n      this.calculateTotal();\r\n    },\r\n    async submit() {\r\n      //this.loading = true;\r\n      this.showDialogPing = true;\r\n      this.open_orders();\r\n    },\r\n    async cancelOrdena(id) {\r\n      try {\r\n        let x = await this.$confirm(\r\n          `Está apunto de cancelar un producto de una orden.`,\r\n          \"Mensaje de Advertencia\",\r\n          {\r\n            confirmButtonText: \"Eliminar\",\r\n            cancelButtonText: \"Cancelar\",\r\n            type: \"warning\",\r\n          }\r\n        );\r\n        if (id && x) {\r\n          const response = await this.$http.delete(`delete-orden/${id}`);\r\n          if (response.status == 200) {\r\n            const { message } = response.data;\r\n            let newOrdenItems = [...this.ordens];\r\n            newOrdenItems = newOrdenItems.filter((n) => n.id != id);\r\n            this.$emit(\"update:ordens\", newOrdenItems);\r\n            this.$eventHub.$emit(\"reloadData\");\r\n            this.$toast.success(message);\r\n          }\r\n        }\r\n      } catch (e) {\r\n        //todo\r\n        console.log(e);\r\n        if (e != \"cancel\") {\r\n          this.$toast.error(\"Ocurrió un error\");\r\n        }\r\n      }\r\n    },\r\n    async ordenReady(id) {\r\n      this.loading = true;\r\n      try {\r\n        const response = await this.$http.get(`ordens-ready/${id}`);\r\n\r\n        const { success, message } = response.data;\r\n        success ? this.$toast.success(message) : this.$toast.error(message);\r\n        if (success) {\r\n          let cloneOrdenItems = [...this.ordens];\r\n          cloneOrdenItems = cloneOrdenItems.map((o) => {\r\n            if (o.id == id) {\r\n              o.status_orden_id = 3;\r\n            }\r\n            return o;\r\n          });\r\n          this.$emit(\"update:ordens\", cloneOrdenItems);\r\n        }\r\n      } catch (e) {\r\n        console.log(e);\r\n        this.$toast.error(\"Ocurrió un error\");\r\n      } finally {\r\n        this.loading = false;\r\n      }\r\n    },\r\n    changeLocalObservation() {\r\n      let ordensModified = [...this.localOrden];\r\n      ordensModified[this.currentLocalOrden].observation =\r\n        this.localObservation;\r\n      this.$emit(\"update:localOrden\", ordensModified);\r\n      this.closeLocalObservationDialog();\r\n    },\r\n    async changeObservation() {\r\n      //this.localObservation\r\n      this.loadingObservation = true;\r\n      const response = await this.$http.post(\"change-observation\", {\r\n        observation: this.observation,\r\n        id: this.currentOrden,\r\n      });\r\n      if (response.status == 200) {\r\n        this.$eventHub.$emit(\"reloadData\");\r\n        let newOrdenItems = [...this.ordens];\r\n        newOrdenItems.find((n) => n.id == this.currentOrden).observations =\r\n          this.observation;\r\n      }\r\n      this.loadingObservation = false;\r\n      this.closeObservationDialog();\r\n    },\r\n    openObservationDialog(id, idx) {\r\n      this.currentOrden = id;\r\n      this.observation = this.ordens[idx].observations;\r\n      this.dialogObservation = true;\r\n    },\r\n    closeObservationDialog() {\r\n      this.dialogObservation = false;\r\n      this.observation = null;\r\n    },\r\n\r\n    openLocalObservationDialog(idx, obs) {\r\n      this.showObservations = true;\r\n      this.currentLocalOrden = idx;\r\n      this.current = obs;\r\n      return;\r\n\r\n      this.localObservation = this.localOrden[idx].observation;\r\n      this.dialogLocalObservation = true;\r\n    },\r\n    closeLocalObservationDialog() {\r\n      this.dialogLocalObservation = false;\r\n      this.currentLocalOrden = null;\r\n      this.localObservation = null;\r\n    },\r\n  },\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/list_ordens.vue","<template>\r\n    <el-dialog\r\n        title=\"Cotización\"\r\n        :visible=\"showDialog\"\r\n        @open=\"open\"\r\n        @close=\"close\"\r\n        v-loading=\"loading\"\r\n    >\r\n        <div class=\"m-2\">\r\n            <div class=\"row\">\r\n                <div class=\"col-md-6\">\r\n                    <label>\r\n                        Cliente\r\n                        <a href=\"#\" @click.prevent=\"showDialogNewPerson = true\"\r\n                            >[+ Nuevo]</a\r\n                        >\r\n                    </label>\r\n                    <el-select\r\n                        v-model=\"form.customer_id\"\r\n                        filterable\r\n                        remote\r\n                        class=\"border-left rounded-left border-info\"\r\n                        popper-class=\"el-select-customers\"\r\n                        dusk=\"customer_id\"\r\n                        placeholder=\"Escriba el nombre o número de documento del cliente\"\r\n                        :remote-method=\"searchRemoteCustomers\"\r\n                        :loading=\"loading_search\"\r\n                    >\r\n                        <el-option\r\n                            v-for=\"option in customers\"\r\n                            :key=\"option.id\"\r\n                            :value=\"option.id\"\r\n                            :label=\"option.description\"\r\n                        ></el-option>\r\n                    </el-select>\r\n                </div>\r\n                <div class=\"col-md-6\">\r\n                    <label>Fecha de emisión</label>\r\n                    <el-date-picker\r\n                        class=\"w-100\"\r\n                        value-format=\"Y-m-d\"\r\n                        v-model=\"form.date_of_issue\"\r\n                    >\r\n                    </el-date-picker>\r\n                </div>\r\n                <div class=\"col-md-6\">\r\n                    <label>Vencimiento</label>\r\n                    <el-date-picker class=\"w-100\" v-model=\"form.date_of_due\">\r\n                    </el-date-picker>\r\n                </div>\r\n            </div>\r\n            <div class=\"row\">\r\n                <div class=\"col-md-12\">\r\n                    <label>Descripción</label>\r\n                    <el-input\r\n                        class=\"w-100\"\r\n                        type=\"textarea\"\r\n                        :rows=\"2\"\r\n                        placeholder=\"Descripción\"\r\n                        v-model=\"form.description\"\r\n                    >\r\n                    </el-input>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div slot=\"footer\" class=\"dialog-footer\">\r\n            <span\r\n                v-if=\"form.total\"\r\n                style=\"margin-right:auto;display:inline-block\"\r\n            >\r\n                <h6>S/. {{ form.total.toFixed(2) }}</h6>\r\n            </span>\r\n            <el-button @click=\"close\">Cancelar</el-button>\r\n            <el-button type=\"primary\" @click=\"submit\">Enviar</el-button>\r\n        </div>\r\n        <person-form\r\n            :showDialog.sync=\"showDialogNewPerson\"\r\n            type=\"customers\"\r\n            :external=\"true\"\r\n        >\r\n        </person-form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport moment from \"moment\";\r\nconst PersonForm = () =>\r\n    import(\"../../../../../../../../resources/js/views/persons/form.vue\");\r\nexport default {\r\n    props: [\"items\", \"cash_id\", \"all_customers\", \"showDialog\"],\r\n    components: { PersonForm },\r\n    data() {\r\n        return {\r\n            form: {},\r\n            showDialogNewPerson: false,\r\n            customers: [],\r\n            resource: \"quotations\",\r\n            loading_search: false,\r\n            percentage_igv: 18,\r\n            loading: false\r\n        };\r\n    },\r\n    created() {\r\n        this.$eventHub.$on(\"reloadDataPersons\", customer_id => {\r\n            this.reloadDataCustomers(customer_id);\r\n        });\r\n    },\r\n    watch: {\r\n        all_customers(newCustomer, _) {\r\n            this.customers = newCustomer.filter(n => n.number != \"88888888\");\r\n        }\r\n    },\r\n    methods: {\r\n        reloadDataCustomers(customer_id) {\r\n            this.$http\r\n                .get(`/documents/search/customer/${customer_id}`)\r\n                .then(response => {\r\n                    this.customers = response.data.customers;\r\n                    this.form.customer_id = customer_id;\r\n                });\r\n        },\r\n\r\n        paymentsOrden() {\r\n            let items = this.items;\r\n            let ordens = items;\r\n            for (let i = 0; i < items.length; i++) {\r\n                let item = items[i];\r\n                ordens[i].food.item.from_unit_type_id = item.type_id;\r\n                ordens[i].food.item.from_unit_type_id_desc =\r\n                    item.type_description;\r\n                ordens[i].food.item.quantity = item.quantity;\r\n                ordens[i].food.item.lotes = item.lotes;\r\n                ordens[i].food.item.lots = item.series;\r\n                ordens[i].food.item.sale_unit_price = item.price;\r\n                ordens[i].food.price = item.price;\r\n            }\r\n            this.form.items = ordens.map(o => o.food.item);\r\n            this.formatItems(ordens);\r\n        },\r\n        formatItems(ordens) {\r\n            this.form.items = this.form.items.map(i => {\r\n                return {\r\n                    ...i,\r\n                    warehouse_id: null,\r\n                    item: i,\r\n                    item_id: i.id,\r\n                    unit_value:\r\n                        i.sale_affectation_igv_type_id == 10\r\n                            ? i.sale_unit_price /\r\n                              (1 + this.percentage_igv / 100)\r\n                            : i.sale_unit_price,\r\n                    quantity: i.quantity,\r\n                    aux_quantity: i.quantity,\r\n                    total_base_igv:\r\n                        i.sale_affectation_igv_type_id == 10\r\n                            ? (i.sale_unit_price * i.quantity) /\r\n                              (1 + this.percentage_igv / 100)\r\n                            : i.sale_unit_price * i.quantity,\r\n                    percentage_igv: this.percentage_igv,\r\n                    total_igv:\r\n                        i.sale_affectation_igv_type_id == 10\r\n                            ? ((i.sale_unit_price * i.quantity) /\r\n                                  (1 + this.percentage_igv / 100)) *\r\n                              (this.percentage_igv / 100)\r\n                            : 0,\r\n                    total_base_isc: 0.0,\r\n                    percentage_isc: 0.0,\r\n                    total_isc: 0.0,\r\n                    total_base_other_taxes: 0.0,\r\n                    percentage_other_taxes: 0.0,\r\n                    total_other_taxes: 0.0,\r\n                    total_taxes:\r\n                        i.sale_affectation_igv_type_id == 10\r\n                            ? ((i.sale_unit_price * i.quantity) /\r\n                                  (1 + this.percentage_igv / 100)) *\r\n                              (this.percentage_igv / 100)\r\n                            : 0,\r\n                    total_value:\r\n                        i.sale_affectation_igv_type_id == 10\r\n                            ? (i.sale_unit_price * i.quantity) /\r\n                              (1 + this.percentage_igv / 100)\r\n                            : i.quantity * i.sale_unit_price,\r\n                    total_charge: 0.0,\r\n                    total_discount: 0.0,\r\n                    total: i.sale_unit_price * i.quantity,\r\n                    price_type_id: \"01\",\r\n                    unit_price: i.sale_unit_price,\r\n                    unit_price_value: i.sale_unit_price,\r\n                    has_igv: i.has_igv,\r\n                    affectation_igv_type_id: i.sale_affectation_igv_type_id,\r\n                    unit_price: i.sale_unit_price,\r\n                    presentation: null,\r\n                    charges: [],\r\n                    discounts: [],\r\n                    attributes: [],\r\n                    affectation_igv_type: i.sale_affectation_igv_type_id\r\n                };\r\n            });\r\n            this.calculateTotal(ordens);\r\n        },\r\n        calculateTotal(ordens) {\r\n            let total_discount = 0;\r\n            let total_charge = 0;\r\n            let total_exportation = 0;\r\n            let total_taxed = 0;\r\n            let total_taxes = 0;\r\n            let total_exonerated = 0;\r\n            let total_unaffected = 0;\r\n            let total_free = 0;\r\n            let total_igv = 0;\r\n            let total_value = 0;\r\n            let total = 0;\r\n            ordens.forEach(orden => {\r\n                total += _.round(\r\n                    orden.food.item.quantity * orden.food.price,\r\n                    2\r\n                );\r\n            });\r\n\r\n            //  total_igv = _.round((total / (1+(this.percentage_igv/100))) * (this.percentage_igv/100), 2);\r\n\r\n            this.form.items.forEach(row => {\r\n                total_discount += parseFloat(row.total_discount);\r\n                total_charge += parseFloat(row.total_charge);\r\n\r\n                total_taxes += parseFloat(row.total_taxes);\r\n                if (row.sale_affectation_igv_type_id === \"10\") {\r\n                    total_igv += _.round(\r\n                        parseFloat(row.total_value) *\r\n                            (this.percentage_igv / 100),\r\n                        2\r\n                    );\r\n                    total_value += _.round(row.total_value, 2);\r\n                    total_taxed += parseFloat(row.total_value);\r\n                }\r\n                if (row.sale_affectation_igv_type_id === \"20\") {\r\n                    total_exonerated += parseFloat(row.total);\r\n                    total_value += _.round(row.total_value, 2);\r\n                }\r\n                if (row.sale_affectation_igv_type_id === \"30\") {\r\n                    total_unaffected += parseFloat(row.total_value);\r\n                    total_value += _.round(row.total_value, 2);\r\n                }\r\n                if (row.sale_affectation_igv_type_id === \"40\") {\r\n                    total_exportation += parseFloat(row.total_value);\r\n                    total_value += _.round(row.total_value, 2);\r\n                }\r\n                if (\r\n                    [\"10\", \"20\", \"30\", \"40\"].indexOf(\r\n                        row.affectation_igv_type_id\r\n                    ) < 0\r\n                ) {\r\n                    total_free += parseFloat(row.total_value);\r\n                }\r\n            });\r\n\r\n            this.form.total_exportation = _.round(total_exportation, 2);\r\n            this.form.total_taxed = _.round(total_taxed, 2);\r\n            this.form.total_taxes = _.round(total_taxes, 2);\r\n            this.form.total_exonerated = _.round(total_exonerated, 2);\r\n            this.form.total_unaffsected = _.round(total_unaffected, 2);\r\n            this.form.total_free = _.round(total_free, 2);\r\n            this.form.total_igv = _.round(total_igv, 2);\r\n            this.form.total_value = _.round(total_value, 2);\r\n            this.form.total = _.round(total, 2);\r\n        },\r\n        searchRemoteCustomers(input) {\r\n            if (input.length > 0) {\r\n                this.loading_search = true;\r\n                let parameters = `input=${input}`;\r\n\r\n                this.$http\r\n                    .get(`/${this.resource}/search/customers?${parameters}`)\r\n                    .then(response => {\r\n                        this.customers = response.data.customers;\r\n                        this.loading_search = false;\r\n                        if (this.customers.length == 0) {\r\n                            this.customers = this.all_customers;\r\n                        }\r\n                    });\r\n            } else {\r\n                this.customers = this.all_customers;\r\n            }\r\n        },\r\n        async submit() {\r\n            try {\r\n                this.loading = true;\r\n                this.form.time_of_issue = moment().format(\"HH:mm:ss\");\r\n                const response = await this.$http.post(\r\n                    `/${this.resource}`,\r\n                    this.form\r\n                );\r\n                if (response.status == 200) {\r\n                    this.$emit(\"limpiarForm\");\r\n                    this.close();\r\n                    this.$toast.success('Cotizacion creada con exito');\r\n                }\r\n            } catch (e) {\r\n                console.log(e);\r\n                this.$toast.error(\"Ocurrió un error\");\r\n                this.$emit(\"\");\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        open() {\r\n            this.customers = this.all_customers;\r\n            this.form = {\r\n                date_of_issue: new Date(),\r\n                currency_type_id: \"PEN\",\r\n                exchange_rate_sale: 1,\r\n                establishment_id: 1,\r\n                prefix: \"COT\",\r\n                purchase_order: null,\r\n                total_prepayment: 0,\r\n                total_charge: 0,\r\n                total_discount: 0,\r\n                total_exportation: 0,\r\n                total_free: 0,\r\n                total_taxed: 0,\r\n                total_unaffected: 0,\r\n                total_exonerated: 0,\r\n                total_igv: 0,\r\n                total_base_isc: 0,\r\n                total_isc: 0,\r\n                total_base_other_taxes: 0,\r\n                total_other_taxes: 0,\r\n                total_taxes: 0,\r\n                total_value: 0,\r\n                total: 0,\r\n                operation_type_id: null,\r\n                date_of_due: null,\r\n                delivery_date: null,\r\n                items: [],\r\n                charges: [],\r\n                discounts: [],\r\n                attributes: [],\r\n                guides: [],\r\n                payment_method_type_id: \"10\",\r\n                additional_information: null,\r\n                shipping_address: null,\r\n                account_number: null,\r\n                terms_condition: null,\r\n                active_terms_condition: false,\r\n                actions: {\r\n                    format_pdf: \"a4\"\r\n                },\r\n                payments: [],\r\n                sale_opportunity_id: null\r\n            };\r\n            this.paymentsOrden();\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/quotation_modal.vue","exports = module.exports = require(\"../../../../../../../../node_modules/css-loader/lib/css-base.js\")(true);\n// imports\n\n\n// module\nexports.push([module.id, \"\\n.el-input-group__prepend {\\r\\n  padding-left: 6px !important;\\r\\n  padding-right: 6px !important;\\n}\\n.custom_input .el-input__inner {\\r\\n  padding: 0 5px !important;\\n}\\n.el-tag + .el-tag {\\r\\n  margin-left: 10px;\\n}\\n.button-new-tag {\\r\\n  margin-left: 10px;\\r\\n  height: 32px;\\r\\n  line-height: 30px;\\r\\n  padding-top: 0;\\r\\n  padding-bottom: 0;\\n}\\n.input-new-tag1 {\\r\\n  width: 70px;\\r\\n  margin-left: 10px;\\r\\n  vertical-align: bottom;\\n}\\n.input-new-tag1 .el-input__inner {\\r\\n  height: 30px !important;\\n}\\r\\n\", \"\", {\"version\":3,\"sources\":[\"D:/laragon/www/restobar/modules/Restaurant/Resources/assets/js/views/pos/partials/modules/Restaurant/Resources/assets/js/views/pos/partials/list_ordens.vue\"],\"names\":[],\"mappings\":\";AA2sCA;EACA,6BAAA;EACA,8BAAA;CACA;AAEA;EACA,0BAAA;CACA;AAEA;EACA,kBAAA;CACA;AAEA;EACA,kBAAA;EACA,aAAA;EACA,kBAAA;EACA,eAAA;EACA,kBAAA;CACA;AAEA;EACA,YAAA;EACA,kBAAA;EACA,uBAAA;CACA;AAEA;EACA,wBAAA;CACA\",\"file\":\"list_ordens.vue\",\"sourcesContent\":[\"<template>\\r\\n  <div v-loading=\\\"ordenLoading\\\">\\r\\n    <div>\\r\\n      <div \\r\\n        v-if=\\\"screenWidth > 600\\\"\\r\\n        class=\\\"d-flex flex-wrap justify-content-between\\\">\\r\\n        <div\\r\\n          v-for=\\\"(option, idx) in optionsMenu\\\"\\r\\n          :key=\\\"idx\\\"\\r\\n          v-show=\\\"option.visible\\\"\\r\\n        >\\r\\n          <div\\r\\n            v-if=\\\"option.visible\\\"\\r\\n            @click=\\\"trigerFunction(option.id)\\\"\\r\\n            class=\\\"\\r\\n              m-1\\r\\n              btn btn-light\\r\\n              rounded\\r\\n              d-flex\\r\\n              flex-column\\r\\n              align-items-center\\r\\n              justify-content-center\\r\\n            \\\"\\r\\n            style=\\\"min-width: 120px; min-height: 75px\\\"\\r\\n          >\\r\\n            <div class=\\\"text-center\\\" style=\\\"margin-bottom: 2px\\\">\\r\\n              <p\\r\\n                style=\\\"margin: 0 !important; padding: 0 !important\\\"\\r\\n                v-for=\\\"(title, idx2) in option.title\\\"\\r\\n                :key=\\\"idx2\\\"\\r\\n              >\\r\\n                {{ title }}\\r\\n              </p>\\r\\n            </div>\\r\\n            <div>\\r\\n              <label v-if=\\\"option.id == 4\\\" style=\\\"margin-left: 2px\\\">{{\\r\\n                ordenInBox.length\\r\\n              }}</label>\\r\\n              <label v-if=\\\"option.id == 5\\\" style=\\\"margin-left: 2px\\\">{{\\r\\n                ordensPending\\r\\n              }}</label>\\r\\n              <i :class=\\\"option.icon\\\"> </i>\\r\\n            </div>\\r\\n          </div>\\r\\n        </div>\\r\\n      </div>\\r\\n      <div v-if=\\\"screenWidth < 600\\\" class=\\\"d-flex flex-wrap\\\">\\r\\n                <div\\r\\n                    v-for=\\\"(option, idx) in optionsMenu\\\"\\r\\n                    :key=\\\"idx\\\"\\r\\n                    v-show=\\\"option.visible\\\"\\r\\n                >\\r\\n                    <div\\r\\n                        v-if=\\\"option.visible && option.id != 5\\\"\\r\\n                        @click=\\\"trigerFunction(option.id)\\\"\\r\\n                        class=\\\"\\r\\n                  m-1\\r\\n                  btn btn-light\\r\\n                  rounded\\r\\n                  d-flex\\r\\n                  flex-column\\r\\n                  align-items-center\\r\\n                  justify-content-center\\r\\n                \\\"\\r\\n                        style=\\\"max-width: 60px; max-height: 60px\\\"\\r\\n                    >\\r\\n                        <div\\r\\n                            class=\\\"text-center\\\"\\r\\n                            style=\\\"margin-bottom: 2px\\\"\\r\\n                        ></div>\\r\\n                        <div>\\r\\n                            <label\\r\\n                                v-if=\\\"option.id == 4\\\"\\r\\n                                style=\\\"margin-left: 2px\\\"\\r\\n                                >{{ ordenInBox.length }}</label\\r\\n                            >\\r\\n\\r\\n                            <i :class=\\\"[option.icon]\\\"> </i>\\r\\n                        </div>\\r\\n                    </div>\\r\\n                </div>\\r\\n            </div>\\r\\n      <div\\r\\n        class=\\\"bg-primary align-items-center rounded-top\\\"\\r\\n        style=\\\"padding-top: 12px\\\"\\r\\n      >\\r\\n        <div class=\\\"row col-12\\\" v-if=\\\"clientTableData.table\\\">\\r\\n          <div>\\r\\n            <h3 class=\\\"text-white\\\">\\r\\n              <strong style=\\\"padding-left: 20px\\\">\\r\\n                {{\\r\\n                  ` ${\\r\\n                    isCreatingOrden\\r\\n                      ? \\\"CREANDO ORDEN\\\"\\r\\n                      : clientTableData.orden_id\\r\\n                      ? `(ORDEN n°\\r\\n                                                                ${clientTableData.orden_id})`\\r\\n                      : \\\"\\\"\\r\\n                  }`\\r\\n                }}\\r\\n              </strong>\\r\\n            </h3>\\r\\n          </div>\\r\\n        </div>\\r\\n        <div\\r\\n          class=\\\"row h5 text-white col-12\\\"\\r\\n          style=\\\"padding-left: 25px\\\"\\r\\n          v-if=\\\"clientTableData.table\\\"\\r\\n        >\\r\\n          <strong>\\r\\n            Mesa {{ clientTableData.table }}- Ref:\\r\\n            {{ clientTableData.ref }}\\r\\n          </strong>\\r\\n        </div>\\r\\n        <div class=\\\"row col-12\\\">\\r\\n          <div class=\\\"h5 text-white col-6\\\" style=\\\"padding-left: 25px\\\">\\r\\n            <strong v-if=\\\"!clientTableData.table\\\"> VENTA DIRECTA</strong>\\r\\n          </div>\\r\\n\\r\\n          <div class=\\\"col-6\\\">\\r\\n            <h3 class=\\\"text-white\\\" style=\\\"text-align: right\\\">\\r\\n              Total S/. {{ (total + totalOrdenItems).toFixed(2) }}\\r\\n            </h3>\\r\\n          </div>\\r\\n        </div>\\r\\n\\r\\n        <!-- <div\\r\\n                    class=\\\"p-1 m-1 col-3 rounded text-center d-flex flex-column align-items-center justify-content-center\\\"\\r\\n                    style=\\\"color:darkblue;font-weight:bold;background-color:gray\\\"\\r\\n                >\\r\\n                    <div>\\r\\n                        <strong>Por enviar </strong>\\r\\n                        S/. {{ total ? total.toFixed(2) : 0.0 }}\\r\\n                    </div>\\r\\n                    <div v-if=\\\"ordens.length != 0\\\">\\r\\n                        <strong>Atendidos </strong>\\r\\n                        S/.\\r\\n                        {{ totalOrdenItems ? totalOrdenItems.toFixed(2) : 0.0 }}\\r\\n                    </div>\\r\\n                </div> -->\\r\\n      </div>\\r\\n      <div :class=\\\"`p-1 bg-primary`\\\">\\r\\n        <div class=\\\"row col-md-12 mx-1\\\">\\r\\n          <div>\\r\\n            <button\\r\\n              alt=\\\"Cobrar La venta \\\"\\r\\n              v-if=\\\"isCreatingOrden == false\\\"\\r\\n              class=\\\"btn btn-light\\\"\\r\\n              type=\\\"button\\\"\\r\\n              @click=\\\"payOrden()\\\"\\r\\n            >\\r\\n              <i class=\\\"fas fa-money-bill-wave\\\"></i> Cobrar\\r\\n            </button>\\r\\n            <button\\r\\n              v-if=\\\"\\r\\n                isCreatingOrden == false &&\\r\\n                clientTableData.table == undefined &&\\r\\n                !configuration.college\\r\\n              \\\"\\r\\n              @click=\\\"openApart\\\"\\r\\n              class=\\\"btn btn-light\\\"\\r\\n              type=\\\"button\\\"\\r\\n            >\\r\\n              <i class=\\\"fas fa-cart-arrow-down\\\"></i>\\r\\n              Aparcar\\r\\n            </button>\\r\\n            <button\\r\\n              v-if=\\\"\\r\\n                isCreatingOrden == true || clientTableData.table == undefined\\r\\n              \\\"\\r\\n              class=\\\"btn btn-light\\\"\\r\\n              type=\\\"button\\\"\\r\\n              @click=\\\"cancelOrden\\\"\\r\\n            >\\r\\n              <i class=\\\"fas fa-trash\\\"></i>\\r\\n              Limpiar\\r\\n            </button>\\r\\n                        <button\\r\\n                            v-if=\\\"localOrden.length != 0\\\"\\r\\n                            class=\\\"btn btn-light\\\"\\r\\n                            type=\\\"button\\\"\\r\\n                            @click=\\\"openQuotation\\\"\\r\\n                        >\\r\\n                            <i class=\\\"fas fa-dollar-sign\\\"></i>\\r\\n                            Cotizar\\r\\n                        </button>\\r\\n                        <button\\r\\n                            v-if=\\\"localOrden.length != 0\\\"\\r\\n                            class=\\\"btn btn-light\\\"\\r\\n                            type=\\\"button\\\"\\r\\n                            @click=\\\"openCredit\\\"\\r\\n                        >\\r\\n                            <i class=\\\"fas fa-dollar-sign\\\"></i>\\r\\n                            A crédito\\r\\n                        </button>\\r\\n            <button\\r\\n              v-if=\\\"\\r\\n                (isCreatingOrden == true || clientTableData.orden_id) &&\\r\\n                localOrden.length != 0\\r\\n           