    <th>\r\n                            ◄ Dinero\r\n                        </th>\r\n                        <th>\r\n                            Cierre\r\n                        </th>\r\n                        <th>\r\n                            ◄ Dinero\r\n                        </th>\r\n                        <th>\r\n                            Detalle\r\n                        </th>\r\n                    </tr>\r\n                </thead>\r\n                <tbody>\r\n                    <tr v-for=\"(box, idx) in boxes\" :key=\"idx\">\r\n                        <td>\r\n                            {{ idx + 1 }}\r\n                        </td>\r\n                        <td>\r\n                            {{ `${box.date_opening}/ ${box.reference_number}` }}\r\n                        </td>\r\n                        <td>\r\n                            {{ box.beginning_balance }}\r\n                        </td>\r\n                        <td>\r\n                            {{ box.date_closed }}\r\n                        </td>\r\n                        <td>\r\n                            {{ box.date_closed ? box.final_balance : \"\" }}\r\n                        </td>\r\n                        <td>\r\n                            <el-button type=\"success\" class=\"text-white\" @click=\"openWhastappForm(box)\">\r\n                                <i class=\"fab fa-whatsapp\" aria-hidden=\"true\"></i>\r\n                            </el-button>\r\n                            <el-button type=\"primary\" @click=\"seeDetail(box)\">\r\n                                Ver\r\n                            </el-button>\r\n                            <el-button class=\"margin-left:10px;\" type=\"primary\" @click=\"openA4(box)\">\r\n                                A4\r\n                            </el-button>\r\n                        </td>\r\n                    </tr>\r\n                </tbody>\r\n            </table>\r\n            <el-pagination @current-change=\"getRecords\" layout=\"total, prev, pager, next\" :total=\"pagination.total\"\r\n                :current-page.sync=\"pagination.current_page\" :page-size=\"Number(pagination.per_page)\">\r\n            </el-pagination>\r\n        </div>\r\n\r\n        <cash-modal v-if=\"currentBox\" :cash.sync=\"currentBox\" :area_id=\"area_id\"\r\n            :showDetail.sync=\"showDetail\"></cash-modal>\r\n        <el-dialog append-to-body width=\"40%\" title=\"Enviar reporte por whatsapp\" :visible.sync=\"showWhatsappForm\">\r\n            <div class=\"p-3\" v-loading=\"loading\" element-loading-text=\"Enviando..\">\r\n                <label for=\"\">Número</label>\r\n                <el-input v-model=\"number\" style=\"width:100%\"></el-input>\r\n                <div class=\"d-flex justify-content-end p-1\">\r\n                    <el-button @click=\"sendWhatsapp\">Enviar</el-button>\r\n                </div>\r\n            </div>\r\n        </el-dialog>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport queryString from \"query-string\";\r\nimport CashModal from \"./cash_modal.vue\";\r\nexport default {\r\n    components: { CashModal },\r\n    props: [\"showHistoryCash\", \"cash_id\", \"area_id\", \"sender\"],\r\n    data() {\r\n        return {\r\n            boxes: [],\r\n            pagination: {},\r\n            number: null,\r\n            loading: false,\r\n            title: \"Sin registros\",\r\n            showDetail: false,\r\n            currentBox: null,\r\n            showWhatsappForm: false,\r\n            message: null,\r\n            resource: null\r\n        };\r\n    },\r\n    methods: {\r\n        openWhastappForm(cash) {\r\n            this.number = null;\r\n            this.message = `Reporte de ${cash.user} ${cash.date_opening}`;\r\n            this.resource = `/restaurant/report-boxes/reports_resumen_type?cash_id=${cash.id}`;\r\n            this.showWhatsappForm = true;\r\n        },\r\n        async sendWhatsapp() {\r\n            if (!this.number || this.number.length != 9 || isNaN(this.number)) {\r\n                return this.$toast.error(\"Ingrese un número válido\");\r\n            }\r\n            this.loading = true;\r\n            try {\r\n                const response = await this.$http.post(\"/whatsapp/historial\", {\r\n                    number: this.number,\r\n                    sender: this.sender,\r\n                    message: this.message,\r\n                    resource: this.resource,\r\n                    file_name: this.message.split(\" \").join(\"-\")\r\n                });\r\n                if (response.status == 200) {\r\n                    this.$toast.success(\"Mensaje enviado\");\r\n                }\r\n            } catch (e) {\r\n                this.$toast.error(\"Mensaje no enviado\");\r\n                console.log(e);\r\n            } finally {\r\n                this.showWhatsappForm = false;\r\n                this.loading = false;\r\n            }\r\n        },\r\n        openA4(cash) {\r\n            window.open(\r\n                `/restaurant/report-boxes/reports_resumen_type?cash_id=${cash.id}`\r\n            );\r\n        },\r\n        seeDetail(cash) {\r\n            this.currentBox = cash;\r\n            this.showDetail = true;\r\n        },\r\n        getQueryParameters() {\r\n            return queryString.stringify({\r\n                page: this.pagination.current_page,\r\n                column: \"state\",\r\n                value: 0\r\n\r\n                // limit: this.limit\r\n            });\r\n        },\r\n        async getRecords() {\r\n            let query = this.getQueryParameters();\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(`cash/records?${query}`);\r\n                if (response.status == 200) {\r\n                    const { data, meta } = response.data;\r\n                    this.boxes = data;\r\n                    console.log(data);\r\n                    if (this.boxes.length != 0) {\r\n                        this.title = `Usuario: ${this.boxes[0].user}`;\r\n                    }\r\n                    this.pagination = meta;\r\n                }\r\n            } catch (e) {\r\n                this.$toast.error(\"Ocurrió un erro\");\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async open() {\r\n            await this.getRecords();\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showHistoryCash\");\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/cash_history.vue","<template>\r\n    <el-dialog\r\n        v-loading=\"loading\"\r\n        :visible=\"showDetail\"\r\n        append-to-body\r\n        @close=\"close\"\r\n        width=\"30%\"\r\n        @open=\"open\"\r\n    >\r\n        <div v-loading=\"loadingPrint\" element-loading-text=\"Imprimiendo...\">\r\n            <div class=\"d-flex justify-content-end\">\r\n                <el-button type=\"primary\" @click=\"print\">\r\n                    <i class=\"fa fa-print\" aria-hidden=\"true\"></i>\r\n                    Imprimir\r\n                </el-button>\r\n            </div>\r\n            <table class=\"table border-bottom\">\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h5\" colspan=\"4\">\r\n                        CÓDIGO DE APERTURA:\r\n                        {{ cash.reference_number }}\r\n                    </td>\r\n                </tr>\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">\r\n                        FECHA ACTUAL\r\n                    </td>\r\n                    <td class=\"text-left h6 \">{{ dateNow }}</td>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">\r\n                        HORA ACTUAL\r\n                    </td>\r\n                    <td class=\"text-left h6\">{{ timeNow }}</td>\r\n                </tr>\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">\r\n                        APERTURA\r\n                    </td>\r\n                    <td class=\"text-left h6\">\r\n                        {{ formatedOpeningDate(cash.opening) }}\r\n                    </td>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">\r\n                        DINERO INICIAL\r\n                    </td>\r\n                    <td class=\"text-left h6\">\r\n                        {{ formatedMoney(cash.beginning_balance) }}\r\n                    </td>\r\n                </tr>\r\n            </table>\r\n\r\n            <table class=\"table border-bottom\">\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h5\" colspan=\"4\">\r\n                        VENTAS REALIZADAS\r\n                    </td>\r\n                </tr>\r\n                <tr\r\n                    v-show=\"data.sum > 0\"\r\n                    v-for=\"(data, idx) in form.sales_detail\"\r\n                    :key=\"idx\"\r\n                >\r\n                    <td\r\n                        class=\"text-left lead-font-weight-700 h6 text-uppercase\"\r\n                    >\r\n                        {{ data.desc }}\r\n                    </td>\r\n                    <td class=\"text-right h6\">\r\n                        {{ formatedMoney(data.sum) }}\r\n                    </td>\r\n                    <td class=\"text-left\"></td>\r\n                    <td class=\"text-left h6\">({{ data.quantity }} pagos)</td>\r\n                </tr>\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">TOTAL</td>\r\n                    <td class=\"text-left\"></td>\r\n                    <td class=\"text-left\"></td>\r\n                    <td class=\"text-left h6\">\r\n                        {{ formatedMoney(form.sales_amount) }}\r\n                    </td>\r\n                </tr>\r\n            </table>\r\n\r\n            <table class=\"table border-bottom\" v-if=\"form.items_detail\">\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h5\" colspan=\"3\">\r\n                        ARTICULOS VENDIDOS\r\n                    </td>\r\n                </tr>\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">ARTICULOS</td>\r\n                    <td class=\"text-left\"></td>\r\n                    <td class=\"text-left h6\">\r\n                        {{ form.items_detail.uniques }}\r\n                    </td>\r\n                </tr>\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">UNIDADES</td>\r\n                    <td class=\"text-left\"></td>\r\n                    <td class=\"text-left h6\">{{ form.items_detail.unds }}</td>\r\n                </tr>\r\n            </table>\r\n\r\n            <table\r\n                class=\"table border-bottom\"\r\n                v-if=\"form.incomes_expenses_cash\"\r\n            >\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h5\" colspan=\"3\">\r\n                        ENTRADAS / SALIDAS DE EFECTIVO\r\n                    </td>\r\n                </tr>\r\n                <tr>\r\n                    <td class=\"text-left h6\">\r\n                        {{ form.incomes_expenses_cash.incomes.quantity }}\r\n                    </td>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">ENTRADAS</td>\r\n                    <td class=\"text-right h6\">\r\n                        {{\r\n                            formatedMoney(\r\n                                form.incomes_expenses_cash.incomes.amount\r\n                            )\r\n                        }}\r\n                    </td>\r\n                </tr>\r\n                <tr>\r\n                    <td class=\"text-left h6\">\r\n                        {{ form.incomes_expenses_cash.expenses.quantity }}\r\n                    </td>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">SALIDAS</td>\r\n                    <td class=\"text-right h6\">\r\n                        {{\r\n                            formatedMoney(\r\n                                form.incomes_expenses_cash.expenses.amount\r\n                            )\r\n                        }}\r\n                    </td>\r\n                </tr>\r\n            </table>\r\n\r\n            <table\r\n                class=\"table border-bottom\"\r\n                v-if=\"form.incomes_expenses_cash\"\r\n            >\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h5\" colspan=\"3\">\r\n                        TOTAL CAJA\r\n                    </td>\r\n                </tr>\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">\r\n                        TOTAL CAJA\r\n                    </td>\r\n                    <td class=\"text-right h6\">\r\n                        {{\r\n                            formatedMoney(\r\n                                Number(\r\n                                    form.incomes_expenses_cash.incomes.amount\r\n                                ) +\r\n                                    Number(form.sales_amount) -\r\n                                    Number(\r\n                                        form.incomes_expenses_cash.expenses\r\n                                            .amount\r\n                                    )\r\n                            )\r\n                        }}\r\n                    </td>\r\n                </tr>\r\n            </table>\r\n\r\n            <table class=\"table border-bottom\" v-if=\"form.documents\">\r\n                <tr>\r\n                    <td class=\"text-left lead-font-weight-700 h5\" colspan=\"2\">\r\n                        LISTADO DE DOCUMENTOS\r\n                    </td>\r\n                </tr>\r\n                <tr v-for=\"(value, key) in form.documents\" :key=\"key\">\r\n                    <td\r\n                        class=\"text-left text-uppercase lead-font-weight-700 h6\"\r\n                    >\r\n                        {{ key }}\r\n                    </td>\r\n                    <td class=\"text-right h6\">\r\n                        {{ formatedMoney(value.total) }}\r\n                    </td>\r\n                </tr>\r\n            </table>\r\n\r\n            <table class=\"table border-bottom\" v-if=\"counter.length != 0\">\r\n                <tr class=\"lead-font-weight-700 h5\">\r\n                    CONTEO DE EFECTIVO\r\n                </tr>\r\n                <tr v-for=\"(coin, idx) in counter\" :key=\"idx\">\r\n                    <td class=\"text-left lead-font-weight-700 h6\">\r\n                        {{ formatedMoney(coin.value) }}\r\n                    </td>\r\n                    <td class=\"text-left h6\">\r\n                        {{ coin.total }}\r\n                    </td>\r\n                    <td class=\"text-right h6\">\r\n                        {{ formatedMoney(coin.value * coin.total) }}\r\n                    </td>\r\n                </tr>\r\n                <tr>\r\n                    <td></td>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">Total</td>\r\n                    <td class=\"text-right h6\">\r\n                        {{ formatedMoney(totalCoins) }}\r\n                    </td>\r\n                </tr>\r\n            </table>\r\n\r\n            <table class=\"table table border-bottom\">\r\n                <tr>\r\n                    <td></td>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">EFECTIVO</td>\r\n                    <td class=\"text-right h6\">\r\n                        {{ formatedMoney(totalCoins) }}\r\n                    </td>\r\n                </tr>\r\n                <tr>\r\n                    <td></td>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">VIRTUAL</td>\r\n                    <td class=\"text-right h6\">\r\n                        {{ formatedMoney(virtualAmount) }}\r\n                    </td>\r\n                </tr>\r\n                <tr>\r\n                    <td></td>\r\n                    <td class=\"text-left lead-font-weight-700 h6\">TOTAL</td>\r\n                    <td class=\"text-right h6\">\r\n                        {{ formatedMoney(virtualAmount + totalCoins) }}\r\n                    </td>\r\n                </tr>\r\n            </table>\r\n        </div>\r\n        <div class=\"m-4\"></div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<style scoped>\r\n.txt_bold {\r\n    font-weight: bolder !important;\r\n}\r\n</style>\r\n<script>\r\nimport moment from \"moment\";\r\nexport default {\r\n    props: [\"cash\", \"showDetail\", \"area_id\"],\r\n    data() {\r\n        return {\r\n            url: \"\",\r\n            loading: false,\r\n            loadingPrint: false,\r\n            form: {},\r\n            moneyFormat: Intl.NumberFormat(\"es-PE\", {\r\n                style: \"currency\",\r\n                currency: \"PEN\",\r\n                minimumFractionDigits: 2\r\n            }),\r\n            itemsUnique: 0,\r\n            itemsUnds: 0,\r\n            counter: [],\r\n            totalCoins: 0,\r\n            virtualAmount: 0,\r\n            dateNow: moment().format(\"D/M/Y\"),\r\n            timeNow: moment().format(\"H:m\")\r\n        };\r\n    },\r\n\r\n    created() {\r\n        let { origin } = window.location;\r\n        this.url = origin;\r\n        this.open();\r\n    },\r\n    methods: {\r\n        init() {\r\n            this.url = \"\";\r\n            this.form = {};\r\n            this.itemsUnique = 0;\r\n            this.itemsUnds = 0;\r\n            this.counter = [];\r\n            this.totalCoins = 0;\r\n            this.virtualAmount = 0;\r\n        },\r\n        async print() {\r\n            try {\r\n                this.loadingPrint = true;\r\n                const response = await this.$http(\r\n                    `cash/get_printer/${this.area_id}`\r\n                );\r\n\r\n                let {\r\n                    data: { printer }\r\n                } = response;\r\n                let config = qz.configs.create(printer, {\r\n                    scaleContent: false\r\n                });\r\n                if (!qz.websocket.isActive()) {\r\n                    await qz.websocket.connect(config);\r\n                }\r\n\r\n                let data = [\r\n                    {\r\n                        type: \"pdf\",\r\n                        format: \"file\",\r\n                        data:\r\n                            this.url +\r\n                            `/restaurant/worker/cash/print-report?cash_id=${this.cash.id}`\r\n                    }\r\n                ];\r\n                await qz.print(config, data);\r\n            } catch (e) {\r\n                this.$toast.error(e.message);\r\n            } finally {\r\n                this.loadingPrint = false;\r\n            }\r\n        },\r\n        formatedMoney(amount) {\r\n            return this.moneyFormat.format(amount);\r\n        },\r\n        formatedCounter() {\r\n            let coins = [...this.cash.counter];\r\n            coins.sort((a, b) => a.value - b.value);\r\n            this.counter = coins.map(c => ({\r\n                value: Number(c.value).toFixed(2),\r\n                total: Number(c.total).toFixed(2)\r\n            }));\r\n            this.totalCoins = this.counter.reduce((a, b) => {\r\n                return a + Number(b.total) * Number(b.value);\r\n            }, 0);\r\n        },\r\n        formatedOpeningDate(openingDate) {\r\n            let [date, time] = openingDate.split(\" \");\r\n            date = date\r\n                .split(\"-\")\r\n                .reverse()\r\n                .join(\"/\");\r\n\r\n            return date + \" \" + time;\r\n        },\r\n        async open() {\r\n            this.init();\r\n            this.formatedCounter();\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `../boxes/records/${this.cash.id}`\r\n                );\r\n                const { data } = response;\r\n                this.form = data;\r\n                let { sales_detail } = data;\r\n\r\n                Object.keys(sales_detail).forEach((k, idx) => {\r\n                    if (k != \"cash\") {\r\n                        this.virtualAmount += Number(sales_detail[k].sum);\r\n                    }\r\n                });\r\n            } catch (e) {\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDetail\", false);\r\n        },\r\n        getTotalSales() {}\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/cash_modal.vue","exports = module.exports = require(\"../../../../../../../../node_modules/css-loader/lib/css-base.js\")(true);\n// imports\n\n\n// module\nexports.push([module.id, \"\\n.txt_bold[data-v-7244c0fc] {\\r\\n    font-weight: bolder !important;\\n}\\r\\n\", \"\", {\"version\":3,\"sources\":[\"D:/laragon/www/restobar/modules/Restaurant/Resources/assets/js/views/pos/partials/modules/Restaurant/Resources/assets/js/views/pos/partials/cash_modal.vue\"],\"names\":[],\"mappings\":\";AA+OA;IACA,+BAAA;CACA\",\"file\":\"cash_modal.vue\",\"sourcesContent\":[\"<template>\\r\\n    <el-dialog\\r\\n        v-loading=\\\"loading\\\"\\r\\n        :visible=\\\"showDetail\\\"\\r\\n        append-to-body\\r\\n        @close=\\\"close\\\"\\r\\n        width=\\\"30%\\\"\\r\\n        @open=\\\"open\\\"\\r\\n    >\\r\\n        <div v-loading=\\\"loadingPrint\\\" element-loading-text=\\\"Imprimiendo...\\\">\\r\\n            <div class=\\\"d-flex justify-content-end\\\">\\r\\n                <el-button type=\\\"primary\\\" @click=\\\"print\\\">\\r\\n                    <i class=\\\"fa fa-print\\\" aria-hidden=\\\"true\\\"></i>\\r\\n                    Imprimir\\r\\n                </el-button>\\r\\n            </div>\\r\\n            <table class=\\\"table border-bottom\\\">\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h5\\\" colspan=\\\"4\\\">\\r\\n                        CÓDIGO DE APERTURA:\\r\\n                        {{ cash.reference_number }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">\\r\\n                        FECHA ACTUAL\\r\\n                    </td>\\r\\n                    <td class=\\\"text-left h6 \\\">{{ dateNow }}</td>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">\\r\\n                        HORA ACTUAL\\r\\n                    </td>\\r\\n                    <td class=\\\"text-left h6\\\">{{ timeNow }}</td>\\r\\n                </tr>\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">\\r\\n                        APERTURA\\r\\n                    </td>\\r\\n                    <td class=\\\"text-left h6\\\">\\r\\n                        {{ formatedOpeningDate(cash.opening) }}\\r\\n                    </td>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">\\r\\n                        DINERO INICIAL\\r\\n                    </td>\\r\\n                    <td class=\\\"text-left h6\\\">\\r\\n                        {{ formatedMoney(cash.beginning_balance) }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n            </table>\\r\\n\\r\\n            <table class=\\\"table border-bottom\\\">\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h5\\\" colspan=\\\"4\\\">\\r\\n                        VENTAS REALIZADAS\\r\\n                    </td>\\r\\n                </tr>\\r\\n                <tr\\r\\n                    v-show=\\\"data.sum > 0\\\"\\r\\n                    v-for=\\\"(data, idx) in form.sales_detail\\\"\\r\\n                    :key=\\\"idx\\\"\\r\\n                >\\r\\n                    <td\\r\\n                        class=\\\"text-left lead-font-weight-700 h6 text-uppercase\\\"\\r\\n                    >\\r\\n                        {{ data.desc }}\\r\\n                    </td>\\r\\n                    <td class=\\\"text-right h6\\\">\\r\\n                        {{ formatedMoney(data.sum) }}\\r\\n                    </td>\\r\\n                    <td class=\\\"text-left\\\"></td>\\r\\n                    <td class=\\\"text-left h6\\\">({{ data.quantity }} pagos)</td>\\r\\n                </tr>\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">TOTAL</td>\\r\\n                    <td class=\\\"text-left\\\"></td>\\r\\n                    <td class=\\\"text-left\\\"></td>\\r\\n                    <td class=\\\"text-left h6\\\">\\r\\n                        {{ formatedMoney(form.sales_amount) }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n            </table>\\r\\n\\r\\n            <table class=\\\"table border-bottom\\\" v-if=\\\"form.items_detail\\\">\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h5\\\" colspan=\\\"3\\\">\\r\\n                        ARTICULOS VENDIDOS\\r\\n                    </td>\\r\\n                </tr>\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">ARTICULOS</td>\\r\\n                    <td class=\\\"text-left\\\"></td>\\r\\n                    <td class=\\\"text-left h6\\\">\\r\\n                        {{ form.items_detail.uniques }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">UNIDADES</td>\\r\\n                    <td class=\\\"text-left\\\"></td>\\r\\n                    <td class=\\\"text-left h6\\\">{{ form.items_detail.unds }}</td>\\r\\n                </tr>\\r\\n            </table>\\r\\n\\r\\n            <table\\r\\n                class=\\\"table border-bottom\\\"\\r\\n                v-if=\\\"form.incomes_expenses_cash\\\"\\r\\n            >\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h5\\\" colspan=\\\"3\\\">\\r\\n                        ENTRADAS / SALIDAS DE EFECTIVO\\r\\n                    </td>\\r\\n                </tr>\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left h6\\\">\\r\\n                        {{ form.incomes_expenses_cash.incomes.quantity }}\\r\\n                    </td>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">ENTRADAS</td>\\r\\n                    <td class=\\\"text-right h6\\\">\\r\\n                        {{\\r\\n                            formatedMoney(\\r\\n                                form.incomes_expenses_cash.incomes.amount\\r\\n                            )\\r\\n                        }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left h6\\\">\\r\\n                        {{ form.incomes_expenses_cash.expenses.quantity }}\\r\\n                    </td>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">SALIDAS</td>\\r\\n                    <td class=\\\"text-right h6\\\">\\r\\n                        {{\\r\\n                            formatedMoney(\\r\\n                                form.incomes_expenses_cash.expenses.amount\\r\\n                            )\\r\\n                        }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n            </table>\\r\\n\\r\\n            <table\\r\\n                class=\\\"table border-bottom\\\"\\r\\n                v-if=\\\"form.incomes_expenses_cash\\\"\\r\\n            >\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h5\\\" colspan=\\\"3\\\">\\r\\n                        TOTAL CAJA\\r\\n                    </td>\\r\\n                </tr>\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">\\r\\n                        TOTAL CAJA\\r\\n                    </td>\\r\\n                    <td class=\\\"text-right h6\\\">\\r\\n                        {{\\r\\n                            formatedMoney(\\r\\n                                Number(\\r\\n                                    form.incomes_expenses_cash.incomes.amount\\r\\n                                ) +\\r\\n                                    Number(form.sales_amount) -\\r\\n                                    Number(\\r\\n                                        form.incomes_expenses_cash.expenses\\r\\n                                            .amount\\r\\n                                    )\\r\\n                            )\\r\\n                        }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n            </table>\\r\\n\\r\\n            <table class=\\\"table border-bottom\\\" v-if=\\\"form.documents\\\">\\r\\n                <tr>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h5\\\" colspan=\\\"2\\\">\\r\\n                        LISTADO DE DOCUMENTOS\\r\\n                    </td>\\r\\n                </tr>\\r\\n                <tr v-for=\\\"(value, key) in form.documents\\\" :key=\\\"key\\\">\\r\\n                    <td\\r\\n                        class=\\\"text-left text-uppercase lead-font-weight-700 h6\\\"\\r\\n                    >\\r\\n                        {{ key }}\\r\\n                    </td>\\r\\n                    <td class=\\\"text-right h6\\\">\\r\\n                        {{ formatedMoney(value.total) }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n            </table>\\r\\n\\r\\n            <table class=\\\"table border-bottom\\\" v-if=\\\"counter.length != 0\\\">\\r\\n                <tr class=\\\"lead-font-weight-700 h5\\\">\\r\\n                    CONTEO DE EFECTIVO\\r\\n                </tr>\\r\\n                <tr v-for=\\\"(coin, idx) in counter\\\" :key=\\\"idx\\\">\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">\\r\\n                        {{ formatedMoney(coin.value) }}\\r\\n                    </td>\\r\\n                    <td class=\\\"text-left h6\\\">\\r\\n                        {{ coin.total }}\\r\\n                    </td>\\r\\n                    <td class=\\\"text-right h6\\\">\\r\\n                        {{ formatedMoney(coin.value * coin.total) }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n                <tr>\\r\\n                    <td></td>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">Total</td>\\r\\n                    <td class=\\\"text-right h6\\\">\\r\\n                        {{ formatedMoney(totalCoins) }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n            </table>\\r\\n\\r\\n            <table class=\\\"table table border-bottom\\\">\\r\\n                <tr>\\r\\n                    <td></td>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">EFECTIVO</td>\\r\\n                    <td class=\\\"text-right h6\\\">\\r\\n                        {{ formatedMoney(totalCoins) }}\\r\\n                    </td>\\r\\n                </tr>\\r\\n                <tr>\\r\\n                    <td></td>\\r\\n                    <td class=\\\"text-left lead-font-weight-700 h6\\\">VIRTUAL</td>\\r\\n                    <td class=\\\"text-right h6\\\">\\